window.QUESTIONS={"ch01": {"入门": [{"t": "tf", "q": "可数名词的复数一般在词尾加 -s。", "a": true, "ex": "如 dog→dogs。"}, {"t": "mc", "q": "选出复数形式正确的一项：", "opts": ["leafs", "leafes", "leaves", "leave"], "a": 2, "ex": "leaf 变 f 为 v 加 -es→leaves。"}, {"t": "mc", "q": "下列属于不可数名词的是：", "opts": ["apple", "information", "book", "desk"], "a": 1, "ex": "information 不可数。"}, {"t": "fill", "q": "用复数：one tomato, two ______ (tomato).", "a": ["tomatoes"], "ex": "辅音+o 的有生命名词加 -es。"}, {"t": "mc", "q": "box 的复数是：", "opts": ["boxes", "boxs", "boxies", "box"], "a": 0, "ex": "以 x 结尾加 -es。"}, {"t": "tf", "q": "child 的复数是 childs。", "a": false, "ex": "child 的复数是 children（不规则）。"}, {"t": "mc", "q": "下列是专有名词的是：", "opts": ["city", "river", "China", "teacher"], "a": 2, "ex": "China 是专有名词，首字母大写。"}, {"t": "fill", "q": "用复数：This is a knife. These are two ______.", "a": ["knives"], "ex": "fe 结尾变 v 加 -es→knives。"}, {"t": "mc", "q": "man 的复数是：", "opts": ["mans", "manes", "men", "mens"], "a": 2, "ex": "man→men（变元音）。"}, {"t": "tf", "q": "water, rice, air 都是不可数名词。", "a": true, "ex": "物质名词不可数。"}], "进阶": [{"t": "mc", "q": "He gave me a useful piece of ______.", "opts": ["advices", "an advice", "advise", "advice"], "a": 3, "ex": "advice 不可数，a piece of advice。"}, {"t": "fill", "q": "用正确形式：This shop sells ______ (woman) shoes.", "a": ["women"], "ex": "woman 修饰复数名词时变 women。"}, {"t": "mc", "q": "The police ______ looking for the thief.", "opts": ["are", "is", "was", "has"], "a": 0, "ex": "police 作主语谓语用复数。"}, {"t": "mc", "q": "表示\"学生们的教室\"，正确的是：", "opts": ["the student's classroom", "the students' classroom", "the students classroom", "the students's classroom"], "a": 1, "ex": "复数名词以 s 结尾，所有格加撇号。"}, {"t": "fill", "q": "用正确形式：I'd like two ______ (glass) of water.", "a": ["glasses"], "ex": "glass 作\"玻璃杯\"可数，加 -es。"}, {"t": "mc", "q": "Would you like some ______?", "opts": ["oranges juice", "orange juices", "oranges juices", "orange juice"], "a": 3, "ex": "juice 不可数；orange 作定语用单数。"}, {"t": "translate", "q": "汉译英：桌子上有一些信息。", "a": ["There is some information on the desk."], "ex": "information 不可数，用 is，不加 -s。"}, {"t": "translate", "q": "汉译英：我需要一张纸。", "a": ["I need a piece of paper.", "I need a sheet of paper."], "ex": "paper 作\"纸\"不可数，用量词 a piece/sheet of。"}, {"t": "fill", "q": "用所有格：This is ______ (Tom) book.", "a": ["Tom's"], "ex": "有生命名词加 's。"}, {"t": "mc", "q": "There are many ______ in the zoo.", "opts": ["sheeps", "sheepes", "sheep", "a sheep"], "a": 2, "ex": "sheep 单复数同形。"}], "复习": [{"t": "mc", "q": "He has written two ______ on this subject.", "opts": ["paper", "papers", "piece of paper", "papered"], "a": 1, "ex": "paper 作\"论文\"可数。"}, {"t": "fill", "q": "用双重所有格：He is a friend of ______ (I).", "a": ["mine"], "ex": "of + 名词性物主代词 mine。"}, {"t": "tf", "q": "trousers, glasses, scissors 等成对物品只有复数形式。", "a": true, "ex": "成对物品名词常用复数。"}, {"t": "mc", "q": "I'd like a ______ of bread.", "opts": ["piece", "bar", "loaf", "sheet"], "a": 2, "ex": "面包用 a loaf of。"}, {"t": "mc", "q": "The number of students ______ growing.", "opts": ["are", "is", "were", "have"], "a": 1, "ex": "the number of 作主语谓语用单数。"}, {"t": "fill", "q": "用正确形式：Both my ______ (foot) hurt.", "a": ["feet"], "ex": "foot→feet（不规则）。"}, {"t": "translate", "q": "汉译英：他的成功是一条重要新闻。", "a": ["His success is a piece of important news.", "His success is an important piece of news."], "ex": "news 不可数，用 a piece of news。"}, {"t": "translate", "q": "汉译英：这家公司有五百名工人。", "a": ["The company has five hundred workers.", "There are five hundred workers in the company."], "ex": "hundred 与具体数字连用不加 -s。"}, {"t": "mc", "q": "Mr. Smith is a friend of my ______.", "opts": ["father", "fathers", "father's", "fathers'"], "a": 2, "ex": "双重所有格：of + 名词's（my father's）。"}, {"t": "tf", "q": "Maths is my favourite subject. 主谓一致正确。", "a": true, "ex": "maths 表单一学科，谓语用单数。"}]}, "ch02": {"入门": [{"t": "mc", "q": "I saw ______ elephant at the zoo.", "opts": ["a", "the", "/", "an"], "a": 3, "ex": "元音音素前用 an。"}, {"t": "tf", "q": "a/an 的选择取决于后面单词的读音。", "a": true, "ex": "看首音素，a university / an hour。"}, {"t": "mc", "q": "This is ______ useful book.", "opts": ["an", "the", "a", "/"], "a": 2, "ex": "useful 首音为辅音 /j/，用 a。"}, {"t": "fill", "q": "填入冠词：I have a dog. ______ dog is black.", "a": ["The", "the"], "ex": "二次提及用 the。"}, {"t": "mc", "q": "There is ______ apple on the table.", "opts": ["a", "the", "an", "/"], "a": 2, "ex": "apple 元音开头用 an。"}, {"t": "tf", "q": "hour 前用 a。", "a": false, "ex": "hour 的 h 不发音，元音开头，用 an hour。"}, {"t": "mc", "q": "______ moon goes around the earth.", "opts": ["A", "The", "An", "/"], "a": 1, "ex": "独一无二的事物用 the。"}, {"t": "fill", "q": "填入冠词或/：We have lunch at twelve. (lunch 前) → ______", "a": ["/"], "ex": "三餐名称前用零冠词。"}, {"t": "mc", "q": "He plays ______ basketball every day.", "opts": ["a", "an", "the", "/"], "a": 3, "ex": "球类运动前用零冠词。"}, {"t": "tf", "q": "play the piano 中 piano 前要用 the。", "a": true, "ex": "乐器名称前用 the。"}], "进阶": [{"t": "mc", "q": "My brother plays ______ guitar and wants to be ______ musician.", "opts": ["a; the", "the; a", "the; an", "/; a"], "a": 1, "ex": "乐器用 the；musician 辅音音用 a。"}, {"t": "mc", "q": "______ sun rises in ______ east.", "opts": ["The; the", "A; an", "/; the", "The; an"], "a": 0, "ex": "独一无二事物和方位用 the。"}, {"t": "fill", "q": "填冠词或/：He goes to ______ school by bike.", "a": ["/"], "ex": "go to school 表\"上学\"，零冠词。"}, {"t": "mc", "q": "______ Greens will come tonight.", "opts": ["A", "An", "/", "The"], "a": 3, "ex": "姓氏复数表一家人用 The。"}, {"t": "mc", "q": "What ______ interesting story!", "opts": ["a", "the", "/", "an"], "a": 3, "ex": "interesting 元音音开头，用 an。"}, {"t": "translate", "q": "汉译英：他每天弹钢琴。", "a": ["He plays the piano every day."], "ex": "乐器前用 the。"}, {"t": "translate", "q": "汉译英：长城是世界上最长的城墙之一。", "a": ["The Great Wall is one of the longest walls in the world."], "ex": "特定专有名词及最高级前用 the。"}, {"t": "fill", "q": "填冠词：This is ______ best film I've ever seen.", "a": ["the"], "ex": "最高级前用 the。"}, {"t": "mc", "q": "He was elected ______ monitor of our class.", "opts": ["a", "an", "/", "the"], "a": 2, "ex": "独一无二的职位用零冠词。"}, {"t": "tf", "q": "in the hospital 与 in hospital 意思相同。", "a": false, "ex": "in hospital 表\"住院\"；加 the 表在那座医院。"}], "复习": [{"t": "mc", "q": "The rich ______ not always happy.", "opts": ["is", "be", "was", "are"], "a": 3, "ex": "the + 形容词表一类人，谓语复数。"}, {"t": "fill", "q": "感叹句填冠词：What ______ beautiful day it is!", "a": ["a"], "ex": "day 可数单数，用 a。"}, {"t": "mc", "q": "He caught me by ______ arm.", "opts": ["a", "an", "/", "the"], "a": 3, "ex": "\"动词+sb+by the+身体部位\"用 the。"}, {"t": "tf", "q": "go to the school 一定表示\"去上学\"。", "a": false, "ex": "go to the school 表去那座具体学校（如家长去）。"}, {"t": "translate", "q": "汉译英：那个穿红衣服的女孩是我妹妹。", "a": ["The girl in red is my sister.", "The girl in the red dress is my sister."], "ex": "特指用 the；in red 固定。"}, {"t": "translate", "q": "汉译英：太阳从东方升起。", "a": ["The sun rises in the east."], "ex": "独一无二事物和方位用 the。"}, {"t": "mc", "q": "He is ______ honest and ______ useful man.", "opts": ["an; a", "a; an", "an; an", "a; a"], "a": 0, "ex": "honest 元音音用 an；useful 辅音音用 a。"}, {"t": "fill", "q": "填冠词或/：______ knowledge is power.", "a": ["/"], "ex": "抽象名词泛指时用零冠词。"}, {"t": "mc", "q": "Beijing is ______ capital of China.", "opts": ["a", "the", "an", "/"], "a": 1, "ex": "独一无二的事物用 the。"}, {"t": "tf", "q": "by bus, by bike 等交通方式前用零冠词。", "a": true, "ex": "by + 交通工具，零冠词。"}]}, "ch03": {"入门": [{"t": "mc", "q": "This book is ______.（我的）", "opts": ["I", "me", "my", "mine"], "a": 3, "ex": "名词性物主代词 mine。"}, {"t": "tf", "q": "each of + 复数名词作主语，谓语用单数。", "a": true, "ex": "each 强调个体。"}, {"t": "mc", "q": "______ of the two boys is from England.", "opts": ["All", "Both", "Every", "Either"], "a": 3, "ex": "两者之中用 either。"}, {"t": "fill", "q": "用反身代词：The girl dressed ______ this morning.", "a": ["herself"], "ex": "主语女性单数用 herself。"}, {"t": "mc", "q": "Please help ______.（你自己）", "opts": ["you", "your", "yourself", "yours"], "a": 2, "ex": "反身代词 yourself。"}, {"t": "tf", "q": "Everyone has his or her own dream. 主谓一致正确。", "a": true, "ex": "everyone 作主语谓语用单数。"}, {"t": "mc", "q": "Is this pen ______?（你的）", "opts": ["you", "your", "yourself", "yours"], "a": 3, "ex": "名词性物主代词 yours。"}, {"t": "fill", "q": "用代词：She loves ______ (she) very much.（宾格）", "a": ["herself"], "ex": "主宾一致时用反身代词 herself。"}, {"t": "mc", "q": "______ is my book; the other is yours.", "opts": ["These", "Those", "This", "Them"], "a": 2, "ex": "单数近指用 This。"}, {"t": "tf", "q": "both 用于两者，all 用于三者及以上。", "a": true, "ex": "both/either 两者；all/every 三者以上。"}], "进阶": [{"t": "mc", "q": "Neither of the answers ______ correct.", "opts": ["is", "are", "were", "have"], "a": 0, "ex": "neither of 作主语谓语用单数。"}, {"t": "mc", "q": "Either you or he ______ to blame.", "opts": ["are", "is", "am", "be"], "a": 1, "ex": "就近原则，与 he 一致。"}, {"t": "fill", "q": "用 it/one：I lost my pen, so I'll buy ______.", "a": ["one"], "ex": "泛指同类用 one。"}, {"t": "mc", "q": "The number of students ______ increasing.", "opts": ["are", "is", "were", "have"], "a": 1, "ex": "the number of 谓语用单数。"}, {"t": "mc", "q": "A number of visitors ______ waiting.", "opts": ["are", "is", "was", "has"], "a": 0, "ex": "a number of 谓语用复数。"}, {"t": "translate", "q": "汉译英：他们俩都不喜欢咖啡。", "a": ["Neither of them likes coffee."], "ex": "neither of 谓语用单数 likes。"}, {"t": "translate", "q": "汉译英：每个学生都有一本词典。", "a": ["Each student has a dictionary.", "Every student has a dictionary."], "ex": "each/every + 单数名词，谓语单数。"}, {"t": "fill", "q": "用代词：______ is necessary to learn English well.（形式主语）", "a": ["It"], "ex": "it 作形式主语。"}, {"t": "mc", "q": "Maths as well as English ______ taught here.", "opts": ["are", "is", "were", "have"], "a": 1, "ex": "A as well as B 谓语与 A 一致。"}, {"t": "tf", "q": "Twenty years is a long time. 主谓一致正确。", "a": true, "ex": "时间/距离等表整体概念，谓语用单数。"}], "复习": [{"t": "mc", "q": "Every boy and every girl ______ a book.", "opts": ["have", "are", "has", "were"], "a": 2, "ex": "every...and every... 谓语用单数。"}, {"t": "fill", "q": "用反身代词：We enjoyed ______ at the party.", "a": ["ourselves"], "ex": "enjoy oneself 玩得开心。"}, {"t": "tf", "q": "None of the students were late. 该说法可接受。", "a": true, "ex": "none of + 复数名词，谓语可单可复。"}, {"t": "mc", "q": "Not only the students but also the teacher ______ excited.", "opts": ["is", "are", "were", "have"], "a": 0, "ex": "not only...but also... 就近原则，与 teacher 一致。"}, {"t": "translate", "q": "汉译英：这些书中没有一本是我的。", "a": ["None of these books is mine.", "None of these books are mine."], "ex": "none of + 复数，谓语可单可复；mine 名词性物主代词。"}, {"t": "translate", "q": "汉译英：要么你要么他必须去。", "a": ["Either you or he has to go.", "Either you or he must go."], "ex": "either...or... 就近，与 he 一致。"}, {"t": "mc", "q": "The teacher with two students ______ coming.", "opts": ["are", "were", "is", "have"], "a": 2, "ex": "with 短语不影响主语，谓语与 teacher 一致。"}, {"t": "fill", "q": "用代词：The weather here is different from ______ in my hometown.", "a": ["that"], "ex": "指代不可数名词用 that。"}, {"t": "tf", "q": "Three quarters of the work has been done. 主谓一致正确。", "a": true, "ex": "分数 of + 不可数名词，谓语用单数。"}, {"t": "mc", "q": "He made a few mistakes, but ______ was serious.", "opts": ["all", "none", "both", "neither"], "a": 1, "ex": "语义\"没有一个是严重的\"用 none。"}]}, "ch04": {"入门": [{"t": "mc", "q": "She is ______ than her sister.", "opts": ["taller", "tall", "tallest", "more tall"], "a": 0, "ex": "两者比较用比较级。"}, {"t": "tf", "q": "修饰 something 等复合不定代词时形容词后置。", "a": true, "ex": "如 something important。"}, {"t": "mc", "q": "This is the ______ film I've ever seen.", "opts": ["good", "better", "well", "best"], "a": 3, "ex": "the + 最高级。"}, {"t": "fill", "q": "用原级：He is as ______ (clever) as his brother.", "a": ["clever"], "ex": "as...as 间用原级。"}, {"t": "mc", "q": "big 的比较级是：", "opts": ["bigger", "biger", "more big", "biggest"], "a": 0, "ex": "重读闭音节双写末字母加 -er。"}, {"t": "tf", "q": "good 的比较级是 gooder。", "a": false, "ex": "good 的比较级是 better（不规则）。"}, {"t": "mc", "q": "This box is ______ than that one.", "opts": ["heavier", "heavy", "heaviest", "more heavy"], "a": 0, "ex": "辅音+y 变 i 加 -er。"}, {"t": "fill", "q": "用最高级：He is the ______ (tall) in his class.", "a": ["tallest"], "ex": "the + 最高级 + 范围。"}, {"t": "mc", "q": "It's ______ today than yesterday.", "opts": ["cold", "coldest", "colder", "more cold"], "a": 2, "ex": "比较级 colder。"}, {"t": "tf", "q": "形容词可作定语和表语。", "a": true, "ex": "a red flower / It is red。"}], "进阶": [{"t": "mc", "q": "She bought a ______ table.", "opts": ["round wooden small", "small round wooden", "wooden small round", "round small wooden"], "a": 1, "ex": "形容词序：大小→形状→材料。"}, {"t": "mc", "q": "This room is twice ______ that one.", "opts": ["bigger than", "as bigger as", "so big as", "as big as"], "a": 3, "ex": "倍数+as+原级+as。"}, {"t": "fill", "q": "用比较级：The harder you work, the ______ (great) progress you make.", "a": ["greater"], "ex": "the+比较级,the+比较级。"}, {"t": "mc", "q": "Of the two answers, this is ______.", "opts": ["the better", "better", "best", "the best"], "a": 0, "ex": "两者间用 the + 比较级。"}, {"t": "mc", "q": "Nothing is ______ than health.", "opts": ["important", "more important", "most important", "the most important"], "a": 1, "ex": "否定词+比较级表最高级含义。"}, {"t": "translate", "q": "汉译英：他比我高得多。", "a": ["He is much taller than I.", "He is much taller than me."], "ex": "much 修饰比较级表程度。"}, {"t": "translate", "q": "汉译英：这是我读过的最有趣的书。", "a": ["This is the most interesting book I have ever read."], "ex": "the + 最高级 + (that) I have ever read。"}, {"t": "fill", "q": "用比较级：The weather is even ______ (bad) than yesterday.", "a": ["worse"], "ex": "bad 的比较级 worse；even 修饰比较级。"}, {"t": "mc", "q": "He is one of the ______ students.", "opts": ["clever", "cleverest", "more clever", "most clever"], "a": 1, "ex": "one of the + 最高级 + 复数名词。"}, {"t": "tf", "q": "the + 形容词可表示一类人，如 the poor。", "a": true, "ex": "the poor = poor people。"}], "复习": [{"t": "mc", "q": "He is ______ student in our class.", "opts": ["the most hard-working", "a most hard-working", "most hard-working", "more hard-working"], "a": 0, "ex": "最高级前加 the。"}, {"t": "tf", "q": "形容词可作宾语补足语，如 paint it red。", "a": true, "ex": "red 补充说明宾语 it。"}, {"t": "fill", "q": "用最高级：This is ______ (expensive) car of all.", "a": ["the most expensive"], "ex": "多音节最高级用 the most。"}, {"t": "mc", "q": "His house is three times ______ as mine.", "opts": ["big", "bigger", "biggest", "as big"], "a": 3, "ex": "倍数+as+原级+as。"}, {"t": "translate", "q": "汉译英：你读得越多，知道得就越多。", "a": ["The more you read, the more you know."], "ex": "the+比较级,the+比较级。"}, {"t": "translate", "q": "汉译英：这个房间是那个的两倍大。", "a": ["This room is twice as big as that one.", "This room is twice the size of that one."], "ex": "倍数表达。"}, {"t": "mc", "q": "There is ______ in today's newspaper.", "opts": ["new nothing", "nothing newer", "nothing new", "new something"], "a": 2, "ex": "形容词修饰复合不定代词时后置。"}, {"t": "fill", "q": "用比较级：He runs ______ (fast) than any other student.", "a": ["faster"], "ex": "比较级+than any other+单数，表最高级含义。"}, {"t": "mc", "q": "The more careful you are, the ______ mistakes you'll make.", "opts": ["few", "fewest", "less", "fewer"], "a": 3, "ex": "修饰可数名词 mistakes 用 fewer。"}, {"t": "tf", "q": "\"越来越冷\"可用 colder and colder 表示。", "a": true, "ex": "比较级 and 比较级表示\"越来越……\"。"}]}, "ch05": {"入门": [{"t": "mc", "q": "He runs very ______.", "opts": ["quick", "quickly", "quicker", "quickest"], "a": 1, "ex": "修饰动词用副词 quickly。"}, {"t": "tf", "q": "频度副词通常放在实义动词前、be 动词后。", "a": true, "ex": "如 often goes / is always。"}, {"t": "mc", "q": "用 hard/hardly：He studies very ______ every day.", "opts": ["hardly", "harder", "hardest", "hard"], "a": 3, "ex": "hard\"努力地\"；hardly\"几乎不\"。"}, {"t": "fill", "q": "用副词：She sang ______ (beautiful) last night.", "a": ["beautifully"], "ex": "修饰动词用副词。"}, {"t": "mc", "q": "She speaks English ______.", "opts": ["good", "well", "best", "better"], "a": 1, "ex": "well 是 good 的副词形式。"}, {"t": "tf", "q": "fast 的副词形式是 fastly。", "a": false, "ex": "fast 副词与形容词同形，没有 fastly。"}, {"t": "mc", "q": "He is ______ late for school.", "opts": ["very", "never", "much", "quite"], "a": 1, "ex": "never 频度副词，放在 be 动词后。"}, {"t": "fill", "q": "用副词：He worked ______ (careful).", "a": ["carefully"], "ex": "形容词加 -ly 变副词。"}, {"t": "mc", "q": "Please come here ______.", "opts": ["quick", "quicker", "quick ly", "quickly"], "a": 3, "ex": "修饰动词 come 用副词。"}, {"t": "tf", "q": "late 既可作形容词也可作副词。", "a": true, "ex": "如 a late bus / arrive late。"}], "进阶": [{"t": "mc", "q": "He speaks English more ______ than I.", "opts": ["fluent", "fluently", "fluenter", "fluence"], "a": 1, "ex": "修饰动词用副词比较级。"}, {"t": "mc", "q": "The book is ______ interesting that I can't put it down.", "opts": ["such", "very", "too", "so"], "a": 3, "ex": "so+形容词+that。"}, {"t": "fill", "q": "用 too/either：I don't like it, and she doesn't ______.", "a": ["either"], "ex": "否定句末用 either。"}, {"t": "mc", "q": "______ do I watch TV; I'm always busy.", "opts": ["Often", "Seldom", "Always", "Usually"], "a": 1, "ex": "seldom 置句首引起部分倒装。"}, {"t": "mc", "q": "He is old enough ______ himself.", "opts": ["dress", "dressing", "to dress", "dressed"], "a": 2, "ex": "enough 后接不定式。"}, {"t": "translate", "q": "汉译英：他工作非常努力，因此通过了考试。", "a": ["He worked so hard that he passed the exam."], "ex": "so+副词+that 结果状语从句。"}, {"t": "translate", "q": "汉译英：我几乎不认识他。", "a": ["I hardly know him."], "ex": "hardly\"几乎不\"。"}, {"t": "fill", "q": "用副词比较级：He came ______ (early) than usual.", "a": ["earlier"], "ex": "early 变 i 加 -er。"}, {"t": "mc", "q": "This film is ______ better than that one.", "opts": ["much", "very", "so", "too"], "a": 0, "ex": "much 修饰比较级。"}, {"t": "tf", "q": "too...to... 表示\"太……以致于不能……\"。", "a": true, "ex": "too young to go to school。"}], "复习": [{"t": "mc", "q": "______ had he got home when it began to rain.", "opts": ["Hardly", "No sooner", "Scarcely", "As soon as"], "a": 1, "ex": "No sooner...than... 置句首部分倒装。"}, {"t": "tf", "q": "enough 修饰形容词或副词时要后置。", "a": true, "ex": "如 old enough。"}, {"t": "fill", "q": "用副词：It was raining; ______ (therefore), we stayed home.", "a": ["therefore"], "ex": "therefore\"因此\"连接副词。"}, {"t": "mc", "q": "Not until midnight ______ to sleep.", "opts": ["he went", "he did go", "went he", "did he go"], "a": 3, "ex": "Not until 置句首主句部分倒装。"}, {"t": "translate", "q": "汉译英：他太累了，不能再走了。", "a": ["He was too tired to walk any further.", "He was too tired to go on walking."], "ex": "too...to... 结构。"}, {"t": "translate", "q": "汉译英：我从未见过这么美的风景。", "a": ["Never have I seen such beautiful scenery.", "I have never seen such beautiful scenery."], "ex": "never 置句首部分倒装（或正常语序）。"}, {"t": "mc", "q": "He runs as ______ as a horse.", "opts": ["faster", "fastest", "more fast", "fast"], "a": 3, "ex": "as...as 间用原级。"}, {"t": "fill", "q": "用 still/already/yet：Has he finished ______?（疑问句末）", "a": ["yet"], "ex": "yet 用于疑问句和否定句末。"}, {"t": "mc", "q": "Only in this way ______ the problem.", "opts": ["we can solve", "we solve", "can we solve", "solve we"], "a": 2, "ex": "Only+状语置句首，主句部分倒装。"}, {"t": "tf", "q": "\"How + 形容词/副词\" 可引导感叹句。", "a": true, "ex": "如 How fast he runs!"}]}, "ch06": {"入门": [{"t": "mc", "q": "There are ______ months in a year.", "opts": ["twelve", "twelveth", "twelfth", "twelves"], "a": 0, "ex": "基数词 twelve。"}, {"t": "fill", "q": "写序数词：He came ______ (1) in the race.", "a": ["first"], "ex": "one→first。"}, {"t": "tf", "q": "hundred 与具体数字连用时不加 -s。", "a": true, "ex": "five hundred。"}, {"t": "mc", "q": "My birthday is on ______ of May.", "opts": ["five", "the fifth", "fifth", "the five"], "a": 1, "ex": "日期用 the + 序数词。"}, {"t": "mc", "q": "three 的序数词是：", "opts": ["threeth", "threed", "third", "thirth"], "a": 2, "ex": "three→third（不规则）。"}, {"t": "tf", "q": "twenty 的序数词是 twentieth。", "a": true, "ex": "y 变 ie 加 th。"}, {"t": "fill", "q": "写序数词：February is the ______ (2) month.", "a": ["second"], "ex": "two→second。"}, {"t": "mc", "q": "I have ______ books.", "opts": ["two hundred", "two hundreds", "two hundreds of", "hundred two"], "a": 0, "ex": "具体数字+hundred 不加 -s。"}, {"t": "tf", "q": "序数词前一般加 the。", "a": true, "ex": "the first, the second。"}, {"t": "fill", "q": "写序数词：This is my ______ (5) lesson.", "a": ["fifth"], "ex": "five→fifth。"}], "进阶": [{"t": "mc", "q": "There are ______ students in the playground.", "opts": ["hundred of", "hundreds", "hundreds of", "two hundreds"], "a": 2, "ex": "hundreds of 表约数。"}, {"t": "fill", "q": "写序数词：September is the ______ (9) month.", "a": ["ninth"], "ex": "nine→ninth（去 e 加 th）。"}, {"t": "mc", "q": "Two ______ of the apples are bad.", "opts": ["third", "three", "thirds", "threes"], "a": 2, "ex": "分子大于1分母用复数。"}, {"t": "tf", "q": "\"20世纪80年代\"可写作 in the 1980s。", "a": true, "ex": "in the + 年份复数。"}, {"t": "mc", "q": "Half of the students ______ girls.", "opts": ["is", "was", "has", "are"], "a": 3, "ex": "half of + 复数名词，谓语复数。"}, {"t": "translate", "q": "汉译英：这座楼有二十层。", "a": ["The building has twenty floors.", "There are twenty floors in the building."], "ex": "基数词+复数名词。"}, {"t": "translate", "q": "汉译英：三分之二的学生通过了考试。", "a": ["Two thirds of the students passed the exam."], "ex": "分数 two thirds + of + 复数。"}, {"t": "fill", "q": "写序数词：He lives on the ______ (3) floor.", "a": ["third"], "ex": "在第三层。"}, {"t": "mc", "q": "There are ______ people here.", "opts": ["thousand of", "thousand", "thousands of", "thousands"], "a": 2, "ex": "thousands of 表约数。"}, {"t": "tf", "q": "分数中分子用基数词，分母用序数词。", "a": true, "ex": "one third, two thirds。"}], "复习": [{"t": "mc", "q": "He lives on ______.", "opts": ["second floor", "the second floor", "the two floor", "floor second"], "a": 1, "ex": "on the + 序数词 + floor。"}, {"t": "fill", "q": "用数词：______ (4/5) of the work is done.", "a": ["Four fifths"], "ex": "分子>1分母加 s。"}, {"t": "tf", "q": "three quarters 表示\"四分之三\"。", "a": true, "ex": "quarter 用复数 quarters。"}, {"t": "mc", "q": "The number 2025 is read as：", "opts": ["two thousands twenty-five", "twenty twenty-fifth", "two thousand and twenty-five", "two zero two five"], "a": 2, "ex": "年份/数字读法。"}, {"t": "translate", "q": "汉译英：我们班有四十五名学生。", "a": ["There are forty-five students in our class.", "Our class has forty-five students."], "ex": "基数词 forty-five。"}, {"t": "translate", "q": "汉译英：他在比赛中得了第一名。", "a": ["He won first place in the competition.", "He came first in the competition."], "ex": "序数词 first。"}, {"t": "mc", "q": "About ______ of the workers are women.", "opts": ["three fourth", "three four", "three fourths", "third four"], "a": 2, "ex": "分数 three fourths。"}, {"t": "fill", "q": "写序数词：Today is the ______ (12) of June.", "a": ["twelfth"], "ex": "twelve→twelfth。"}, {"t": "mc", "q": "In ______, many things changed.", "opts": ["the 1990s", "1990s", "1990's", "the 1990"], "a": 0, "ex": "年代用 in the 1990s。"}, {"t": "tf", "q": "hundreds of, thousands of 表示\"成百上千\"。", "a": true, "ex": "约数表达。"}]}, "ch07": {"入门": [{"t": "mc", "q": "下列作系动词的是：", "opts": ["He runs fast.", "The flower smells sweet.", "She reads books.", "They sing."], "a": 1, "ex": "smell 系动词接形容词。"}, {"t": "tf", "q": "及物动词后跟宾语，不及物动词后不直接跟宾语。", "a": true, "ex": "及物/不及物区别。"}, {"t": "mc", "q": "Please ______ the door.", "opts": ["closes", "closed", "close", "closing"], "a": 2, "ex": "祈使句用原形。"}, {"t": "fill", "q": "用正确形式：The story ______ (sound) interesting.", "a": ["sounds"], "ex": "系动词 sound 第三人称单数。"}, {"t": "mc", "q": "He ______ a teacher.", "opts": ["are", "am", "is", "be"], "a": 2, "ex": "系动词 be，主语 he 用 is。"}, {"t": "tf", "q": "look, feel, taste 都可作系动词。", "a": true, "ex": "感官系动词接形容词。"}, {"t": "mc", "q": "The leaves ______ green in spring.", "opts": ["turns", "turned to", "turning", "turn"], "a": 3, "ex": "turn 系动词\"变得\"，主语复数用原形。"}, {"t": "fill", "q": "用正确形式：It ______ (taste) delicious.", "a": ["tastes"], "ex": "系动词 taste 第三人称单数。"}, {"t": "mc", "q": "They ______ football every afternoon.", "opts": ["plays", "playing", "play", "played"], "a": 2, "ex": "主语复数用原形。"}, {"t": "tf", "q": "实义动词分及物动词和不及物动词。", "a": true, "ex": "按是否带宾语划分。"}], "进阶": [{"t": "mc", "q": "The meeting ______ for two hours.", "opts": ["lasted", "spent", "took", "cost"], "a": 0, "ex": "last 不及物，接时间段。"}, {"t": "mc", "q": "It ______ me two hours to finish it.", "opts": ["spent", "cost", "paid", "took"], "a": 3, "ex": "It takes sb. time to do。"}, {"t": "fill", "q": "用正确形式：He ______ (lie) on the grass now.", "a": ["is lying"], "ex": "lie→lying，现在进行时。"}, {"t": "mc", "q": "He ______ 100 yuan on the book.", "opts": ["cost", "spent", "took", "paid"], "a": 1, "ex": "spend money on sth。"}, {"t": "mc", "q": "选出必须接宾语的及物动词：", "opts": ["arrive", "happen", "raise", "rise"], "a": 2, "ex": "raise 及物；rise 不及物。"}, {"t": "translate", "q": "汉译英：完成作业花了我两个小时。", "a": ["It took me two hours to finish my homework.", "I spent two hours finishing my homework."], "ex": "take/spend 时间表达。"}, {"t": "translate", "q": "汉译英：这本书花了我五十元。", "a": ["The book cost me fifty yuan.", "I paid fifty yuan for the book."], "ex": "cost/pay for 表达。"}, {"t": "fill", "q": "用 rise/raise：The sun ______ (rise) in the east.", "a": ["rises"], "ex": "rise 不及物，第三人称单数。"}, {"t": "mc", "q": "He ______ his hand to answer.", "opts": ["rose", "arose", "risen", "raised"], "a": 3, "ex": "raise 及物\"举起\"。"}, {"t": "tf", "q": "系动词 become, get, turn 后可接形容词。", "a": true, "ex": "turn red, get angry。"}], "复习": [{"t": "mc", "q": "He often ______ his homework before dinner.", "opts": ["does", "do", "did", "doing"], "a": 0, "ex": "一般现在时第三人称单数。"}, {"t": "tf", "q": "系动词后接的成分是表语。", "a": true, "ex": "如 He is happy。"}, {"t": "fill", "q": "用 lie/lay：He ______ (lay) the book on the desk just now.", "a": ["laid"], "ex": "lay（放置）及物，过去式 laid。"}, {"t": "mc", "q": "Prices have ______ recently.", "opts": ["raised", "arisen", "risen", "rose"], "a": 2, "ex": "rise（上涨）不及物，过去分词 risen。"}, {"t": "translate", "q": "汉译英：这汤尝起来很好。", "a": ["The soup tastes good.", "The soup tastes nice."], "ex": "taste 系动词接形容词。"}, {"t": "translate", "q": "汉译英：会议持续了三个小时。", "a": ["The meeting lasted three hours.", "The meeting lasted for three hours."], "ex": "last 不及物接时间段。"}, {"t": "mc", "q": "Money doesn't ______ on trees.", "opts": ["grows", "grew", "growing", "grow"], "a": 3, "ex": "doesn't 后用动词原形。"}, {"t": "fill", "q": "用正确形式：The flowers ______ (smell) sweet.", "a": ["smell"], "ex": "系动词 smell，主语复数用原形。"}, {"t": "mc", "q": "What happened ______ you yesterday?", "opts": ["with", "on", "to", "at"], "a": 2, "ex": "happen to sb 固定搭配。"}, {"t": "tf", "q": "borrow 和 lend 意思相同，可互换。", "a": false, "ex": "borrow\"借入\"，lend\"借出\"，方向相反。"}]}, "ch08": {"入门": [{"t": "mc", "q": "You ______ smoke here. It's not allowed.", "opts": ["needn't", "may not", "mustn't", "don't have to"], "a": 2, "ex": "mustn't 表禁止。"}, {"t": "tf", "q": "can 和 be able to 都可表示\"能够\"。", "a": true, "ex": "can = be able to。"}, {"t": "mc", "q": "—May I come in? —Yes, you ______.", "opts": ["need", "must", "may", "would"], "a": 2, "ex": "对 May I 肯定回答用 may/can。"}, {"t": "fill", "q": "用情态动词（过去能力）：When I was five, I ______ swim.", "a": ["could"], "ex": "could 过去能力。"}, {"t": "mc", "q": "You ______ be tired after the long walk.", "opts": ["can", "need", "dare", "must"], "a": 3, "ex": "must 表肯定推测。"}, {"t": "tf", "q": "情态动词后接动词原形。", "a": true, "ex": "如 can do, must go。"}, {"t": "mc", "q": "We ______ finish it today; there's no hurry.", "opts": ["mustn't", "can't", "needn't", "may not"], "a": 2, "ex": "needn't 不必。"}, {"t": "fill", "q": "用 should：You ______ listen to your teacher.", "a": ["should"], "ex": "should 应该。"}, {"t": "mc", "q": "______ you please open the window?", "opts": ["Must", "Could", "Need", "Dare"], "a": 1, "ex": "Could you...? 礼貌请求。"}, {"t": "tf", "q": "may 可以表示请求许可，也可表示推测\"可能\"。", "a": true, "ex": "May I...? / It may rain。"}], "进阶": [{"t": "mc", "q": "—Must I hand it in now? —No, you ______.", "opts": ["mustn't", "needn't", "can't", "shouldn't"], "a": 1, "ex": "对 must 否定回答用 needn't。"}, {"t": "mc", "q": "The light is on, so he ______ be at home.", "opts": ["must", "can't", "needn't", "mustn't"], "a": 0, "ex": "must 肯定推测。"}, {"t": "mc", "q": "He ______ be at school; I saw him at home.", "opts": ["must", "can't", "may", "should"], "a": 1, "ex": "can't 否定推测。"}, {"t": "fill", "q": "用情态动词：You ______ (应该) see a doctor.", "a": ["should"], "ex": "should 建议。"}, {"t": "mc", "q": "You ______ have told her; now it's a problem.", "opts": ["shouldn't", "needn't", "mustn't", "can't"], "a": 0, "ex": "shouldn't have done 本不该做。"}, {"t": "translate", "q": "汉译英：你现在不必交作业。", "a": ["You needn't hand in your homework now.", "You don't have to hand in your homework now."], "ex": "needn't / don't have to 表不必。"}, {"t": "translate", "q": "汉译英：他一定在家，因为灯亮着。", "a": ["He must be at home, because the light is on."], "ex": "must 表肯定推测。"}, {"t": "fill", "q": "用 could/couldn't：I ______ (不能) understand him at all.", "a": ["couldn't"], "ex": "couldn't 表过去不能。"}, {"t": "mc", "q": "Shall I open the door? — Yes, ______.", "opts": ["please do", "please", "you shall", "do please"], "a": 0, "ex": "please do 表同意。"}, {"t": "tf", "q": "\"must + have + 过去分词\"表对过去的肯定推测。", "a": true, "ex": "He must have left。"}], "复习": [{"t": "mc", "q": "He ______ have finished it; it's only nine now.", "opts": ["must", "needn't", "may not", "can't"], "a": 3, "ex": "can't have done 对过去否定推测。"}, {"t": "tf", "q": "needn't have done 表示\"本不必做却做了\"。", "a": true, "ex": "如 You needn't have come。"}, {"t": "fill", "q": "用情态动词：She ______ (可能) have missed the train.", "a": ["may", "might", "could"], "ex": "may/might have done 对过去推测。"}, {"t": "mc", "q": "You ______ have bought it; we already had one.", "opts": ["mustn't", "can't", "shouldn't", "needn't"], "a": 3, "ex": "needn't have done 本不必做。"}, {"t": "translate", "q": "汉译英：你本不该把秘密告诉他。", "a": ["You shouldn't have told him the secret."], "ex": "shouldn't have done。"}, {"t": "translate", "q": "汉译英：他不可能已经完成作业了。", "a": ["He can't have finished his homework."], "ex": "can't have done 对过去否定推测。"}, {"t": "mc", "q": "When I was young, I ______ run very fast.", "opts": ["could", "can", "may", "must"], "a": 0, "ex": "could 过去能力。"}, {"t": "fill", "q": "用 must/can't：The ground is wet; it ______ have rained.", "a": ["must"], "ex": "must have done 对过去肯定推测。"}, {"t": "mc", "q": "______ I borrow your pen? — Sure.", "opts": ["May", "Must", "Need", "Shall"], "a": 0, "ex": "May I...? 请求许可。"}, {"t": "tf", "q": "dare 和 need 既可作情态动词也可作实义动词。", "a": true, "ex": "如 Need I go? / I need to go。"}]}, "ch09": {"入门": [{"t": "mc", "q": "The meeting is ______ Monday morning.", "opts": ["in", "at", "on", "by"], "a": 2, "ex": "具体某天早晨用 on。"}, {"t": "tf", "q": "in 用于较长时段，at 用于具体时刻。", "a": true, "ex": "in 2020 / at 6。"}, {"t": "mc", "q": "There is a picture ______ the wall.", "opts": ["in", "at", "to", "on"], "a": 3, "ex": "on the wall 表表面。"}, {"t": "fill", "q": "填介词：I get up ______ seven o'clock.", "a": ["at"], "ex": "具体时刻用 at。"}, {"t": "mc", "q": "My birthday is ______ May.", "opts": ["on", "in", "at", "by"], "a": 1, "ex": "月份前用 in。"}, {"t": "tf", "q": "at night 表示\"在夜里\"。", "a": true, "ex": "固定搭配 at night。"}, {"t": "mc", "q": "The cat is ______ the table.（下面）", "opts": ["under", "on", "in", "at"], "a": 0, "ex": "under 表\"在……下面\"。"}, {"t": "fill", "q": "填介词：He lives ______ Beijing.", "a": ["in"], "ex": "大地点用 in。"}, {"t": "mc", "q": "School begins ______ September.", "opts": ["on", "at", "in", "to"], "a": 2, "ex": "月份用 in。"}, {"t": "tf", "q": "between 用于两者之间，among 用于三者及以上。", "a": true, "ex": "between A and B / among many。"}], "进阶": [{"t": "mc", "q": "The shop is open ______ 9 a.m. ______ 6 p.m.", "opts": ["from; to", "in; at", "at; on", "since; for"], "a": 0, "ex": "from...to... 时间段。"}, {"t": "fill", "q": "填介词：He has lived here ______ 2015.", "a": ["since"], "ex": "since + 时间点。"}, {"t": "mc", "q": "She is good ______ singing.", "opts": ["in", "at", "on", "for"], "a": 1, "ex": "be good at。"}, {"t": "mc", "q": "He walked ______ the room.（进入）", "opts": ["into", "in", "onto", "to"], "a": 0, "ex": "into 表进入。"}, {"t": "mc", "q": "We have studied English ______ three years.", "opts": ["since", "for", "in", "at"], "a": 1, "ex": "for + 时间段。"}, {"t": "translate", "q": "汉译英：他擅长打篮球。", "a": ["He is good at playing basketball."], "ex": "be good at doing。"}, {"t": "translate", "q": "汉译英：火车准时到达了。", "a": ["The train arrived on time."], "ex": "on time 准时。"}, {"t": "fill", "q": "填介词：The train arrived ______ time.（准时）", "a": ["on"], "ex": "on time 准时；in time 及时。"}, {"t": "mc", "q": "He succeeded ______ passing the exam.", "opts": ["at", "on", "in", "for"], "a": 2, "ex": "succeed in doing。"}, {"t": "tf", "q": "表示\"用某种语言\"用 in，如 in English。", "a": true, "ex": "in + 语言。"}], "复习": [{"t": "mc", "q": "He is afraid ______ snakes.", "opts": ["at", "for", "with", "of"], "a": 3, "ex": "be afraid of。"}, {"t": "tf", "q": "by 可表示\"乘坐（交通工具）\"，如 by bus。", "a": true, "ex": "by + 交通工具。"}, {"t": "fill", "q": "填介词：Thank you ______ your help.", "a": ["for"], "ex": "thank sb for sth。"}, {"t": "mc", "q": "He divided the apple ______ four pieces.", "opts": ["in", "to", "onto", "into"], "a": 3, "ex": "divide...into... 分成。"}, {"t": "translate", "q": "汉译英：我从2010年起就住在这里。", "a": ["I have lived here since 2010."], "ex": "since + 时间点 + 完成时。"}, {"t": "translate", "q": "汉译英：他因迟到而道歉。", "a": ["He apologized for being late."], "ex": "apologize for doing。"}, {"t": "mc", "q": "This book is different ______ that one.", "opts": ["with", "to", "from", "of"], "a": 2, "ex": "be different from。"}, {"t": "fill", "q": "填介词：He is interested ______ science.", "a": ["in"], "ex": "be interested in。"}, {"t": "mc", "q": "We arrived ______ the station at noon.", "opts": ["to", "in", "on", "at"], "a": 3, "ex": "arrive at + 小地点。"}, {"t": "tf", "q": "because of, instead of, in front of 都是复合介词。", "a": true, "ex": "复合介词后接名词。"}]}, "ch10": {"入门": [{"t": "mc", "q": "I like apples ______ bananas.", "opts": ["but", "or", "and", "so"], "a": 2, "ex": "and 并列。"}, {"t": "tf", "q": "because 与 so 不能在同一句中同时使用。", "a": true, "ex": "只能用其一。"}, {"t": "mc", "q": "Hurry up, ______ you'll miss the bus.", "opts": ["and", "or", "but", "so"], "a": 1, "ex": "祈使句+or 表否则。"}, {"t": "fill", "q": "用 and/but：He is poor ______ happy.", "a": ["but"], "ex": "转折用 but。"}, {"t": "mc", "q": "Is it a boy ______ a girl?", "opts": ["and", "but", "so", "or"], "a": 3, "ex": "选择用 or。"}, {"t": "tf", "q": "both...and... 连接主语时谓语用复数。", "a": true, "ex": "Both A and B are...。"}, {"t": "mc", "q": "He was tired, ______ he kept working.", "opts": ["so", "and", "but", "or"], "a": 2, "ex": "转折用 but。"}, {"t": "fill", "q": "用 or：Work hard, ______ you'll fail.", "a": ["or"], "ex": "祈使句+or 表否则。"}, {"t": "mc", "q": "Work hard, ______ you'll succeed.", "opts": ["and", "or", "but", "so"], "a": 0, "ex": "祈使句+and 表那么就。"}, {"t": "tf", "q": "and, but, or, so 都是并列连词。", "a": true, "ex": "连接并列成分。"}], "进阶": [{"t": "mc", "q": "______ he is young, he knows a lot.", "opts": ["But", "Although", "Because", "So"], "a": 1, "ex": "Although 让步，不与 but 连用。"}, {"t": "fill", "q": "用 neither...nor：______ he ______ I am to blame.", "a": ["Neither; nor"], "ex": "Neither...nor... 就近一致。"}, {"t": "mc", "q": "______ it was raining, the match was cancelled.", "opts": ["Although", "While", "If", "As"], "a": 3, "ex": "As 引导原因。"}, {"t": "mc", "q": "Either Tom ______ Jack will go.", "opts": ["and", "or", "nor", "but"], "a": 1, "ex": "either...or...。"}, {"t": "mc", "q": "Not only ______ English, but he also speaks French.", "opts": ["he speaks", "speaks he", "does he speak", "he does speak"], "a": 2, "ex": "not only 置句首部分倒装。"}, {"t": "translate", "q": "汉译英：他和我都不在场。", "a": ["Neither he nor I was there.", "Neither he nor I am there."], "ex": "neither...nor... 就近一致。"}, {"t": "translate", "q": "汉译英：虽然他很累，但仍坚持工作。", "a": ["Although he was tired, he kept working.", "Though he was tired, he still kept working."], "ex": "although/though 不与 but 连用。"}, {"t": "fill", "q": "用 both...and：______ Tom ______ Jack like football.", "a": ["Both; and"], "ex": "谓语用复数。"}, {"t": "mc", "q": "He didn't come ______ he was ill.", "opts": ["because of", "so", "because", "therefore"], "a": 2, "ex": "because + 句子。"}, {"t": "tf", "q": "either...or... 连接主语时谓语遵循就近原则。", "a": true, "ex": "与最近的主语一致。"}], "复习": [{"t": "mc", "q": "______ you hurry, you'll be late.", "opts": ["Unless", "If", "Because", "Although"], "a": 0, "ex": "Unless = if...not。"}, {"t": "tf", "q": "as soon as 表示\"一……就……\"。", "a": true, "ex": "时间连词。"}, {"t": "fill", "q": "用连词：______ (尽管) it was late, he went on working.", "a": ["Although", "Though"], "ex": "让步连词。"}, {"t": "mc", "q": "He will not come ______ he is invited.", "opts": ["unless", "if", "because", "although"], "a": 0, "ex": "unless 除非。"}, {"t": "translate", "q": "汉译英：要么你去，要么我去。", "a": ["Either you go or I go.", "Either you or I will go."], "ex": "either...or...。"}, {"t": "translate", "q": "汉译英：他既不抽烟也不喝酒。", "a": ["He neither smokes nor drinks."], "ex": "neither...nor... 连接谓语。"}, {"t": "mc", "q": "I'll wait ______ you come back.", "opts": ["unless", "although", "until", "because"], "a": 2, "ex": "until 直到。"}, {"t": "fill", "q": "用 while/when：______ I was reading, the phone rang.", "a": ["While", "When"], "ex": "表\"当……时\"。"}, {"t": "mc", "q": "______ hard he tried, he couldn't do it.", "opts": ["Whatever", "However", "No matter", "Although"], "a": 1, "ex": "However + 副词，引导让步。"}, {"t": "tf", "q": "so that 可引导目的状语从句。", "a": true, "ex": "so that 以便。"}]}, "ch11": {"入门": [{"t": "mc", "q": "\"Birds fly.\" 属于哪种句型？", "opts": ["主谓宾 SVO", "主系表 SVP", "主谓双宾", "主谓 SV"], "a": 3, "ex": "fly 不及物，SV。"}, {"t": "tf", "q": "系动词后面接的成分叫表语。", "a": true, "ex": "如 He is a teacher。"}, {"t": "mc", "q": "\"I like music.\" 中 music 作：", "opts": ["宾语", "主语", "表语", "定语"], "a": 0, "ex": "like 的宾语。"}, {"t": "fill", "q": "判断句型(SV/SVO/SVP)：The soup tastes good. → ______", "a": ["SVP"], "ex": "taste 系动词，主系表。"}, {"t": "mc", "q": "\"He is a doctor.\" 属于：", "opts": ["SV", "SVO", "SVP", "SVOC"], "a": 2, "ex": "is 系动词，a doctor 表语。"}, {"t": "tf", "q": "主语通常位于谓语之前。", "a": true, "ex": "陈述句正常语序。"}, {"t": "mc", "q": "\"She sings.\" 中 sings 是：", "opts": ["主语", "谓语", "宾语", "表语"], "a": 1, "ex": "sings 是谓语动词。"}, {"t": "fill", "q": "判断句型：The baby is sleeping. → ______", "a": ["SV"], "ex": "sleep 不及物，SV。"}, {"t": "mc", "q": "\"We study English.\" 属于：", "opts": ["SV", "SVO", "SVP", "SVOC"], "a": 1, "ex": "study 及物接宾语。"}, {"t": "tf", "q": "定语用来修饰名词或代词。", "a": true, "ex": "如 a red flower 中 red 是定语。"}], "进阶": [{"t": "mc", "q": "\"He gave me a book.\" 属于：", "opts": ["SVO", "SVOC", "SVP", "SVoO"], "a": 3, "ex": "双宾语 SVoO。"}, {"t": "mc", "q": "\"We made him monitor.\" 中 monitor 作：", "opts": ["宾语", "表语", "宾语补足语", "定语"], "a": 2, "ex": "宾补，SVOC。"}, {"t": "fill", "q": "判断句型：She showed me her photos. → ______", "a": ["SVoO"], "ex": "show sb sth 双宾语。"}, {"t": "mc", "q": "下列属于 SVOC 的是：", "opts": ["He runs fast.", "They elected him chairman.", "I have a pen.", "She is happy."], "a": 1, "ex": "him 宾语，chairman 宾补。"}, {"t": "mc", "q": "\"The weather has turned cold.\" 属于：", "opts": ["SV", "SVP", "SVO", "SVOC"], "a": 1, "ex": "turn 系动词，cold 表语。"}, {"t": "translate", "q": "汉译英：他给了我一支钢笔。", "a": ["He gave me a pen.", "He gave a pen to me."], "ex": "give sb sth / give sth to sb。"}, {"t": "translate", "q": "汉译英：我们选他当班长。", "a": ["We elected him monitor.", "We made him our monitor."], "ex": "SVOC 结构。"}, {"t": "fill", "q": "判断句型：He kept the door open. → ______", "a": ["SVOC"], "ex": "open 作宾补。"}, {"t": "mc", "q": "\"His job is to teach.\" 中 to teach 作：", "opts": ["主语", "宾语", "状语", "表语"], "a": 3, "ex": "系动词后不定式作表语。"}, {"t": "tf", "q": "宾语补足语补充说明宾语。", "a": true, "ex": "如 keep the room clean。"}], "复习": [{"t": "mc", "q": "\"There is a book on the desk.\" 中 there 是：", "opts": ["引导词", "主语", "状语", "表语"], "a": 0, "ex": "there 为引导词，真正主语后置。"}, {"t": "tf", "q": "同位语用来进一步说明前面的名词。", "a": true, "ex": "如 Mr. Li, our teacher。"}, {"t": "fill", "q": "判断句型：They appointed her manager. → ______", "a": ["SVOC"], "ex": "manager 作宾补。"}, {"t": "mc", "q": "\"I find the book interesting.\" 中 interesting 作：", "opts": ["宾语补足语", "定语", "表语", "状语"], "a": 0, "ex": "补充说明宾语 the book。"}, {"t": "translate", "q": "汉译英：这个消息使我们很高兴。", "a": ["The news made us happy.", "The news made us very happy."], "ex": "make sb + 形容词，SVOC。"}, {"t": "translate", "q": "汉译英：天气变冷了。", "a": ["The weather has turned cold.", "It has become cold."], "ex": "turn/become 系动词，主系表。"}, {"t": "mc", "q": "\"She gave the poor some money.\" 中 the poor 作：", "opts": ["直接宾语", "宾补", "间接宾语", "定语"], "a": 2, "ex": "间接宾语指人。"}, {"t": "fill", "q": "判断句型：Gradually the smile appeared. → ______", "a": ["SV"], "ex": "appear 不及物。"}, {"t": "mc", "q": "下列含双宾语的是：", "opts": ["He sang a song.", "He felt tired.", "He ran away.", "He told me a story."], "a": 3, "ex": "tell sb sth 双宾语。"}, {"t": "tf", "q": "五大基本句型是 SV、SVP、SVO、SVoO、SVOC。", "a": true, "ex": "英语五大基本句型。"}]}, "ch12": {"入门": [{"t": "tf", "q": "英语时态由\"时间\"和\"状态\"两个维度构成。", "a": true, "ex": "时间与体的组合。"}, {"t": "mc", "q": "表示\"经常性动作\"用：", "opts": ["现在进行时", "一般现在时", "一般过去时", "现在完成时"], "a": 1, "ex": "一般现在时表习惯。"}, {"t": "mc", "q": "表示\"正在进行\"用：", "opts": ["进行时", "一般现在时", "完成时", "将来时"], "a": 0, "ex": "be+doing。"}, {"t": "fill", "q": "\"动作已完成并对现在有影响\"用______时。", "a": ["现在完成", "完成"], "ex": "现在完成时。"}, {"t": "mc", "q": "will do 表示哪种时态？", "opts": ["一般现在时", "一般过去时", "一般将来时", "现在完成时"], "a": 2, "ex": "一般将来时。"}, {"t": "tf", "q": "did 是动词 do 的过去式。", "a": true, "ex": "一般过去时。"}, {"t": "mc", "q": "was/were doing 是哪种时态？", "opts": ["现在进行时", "将来进行时", "现在完成时", "过去进行时"], "a": 3, "ex": "过去进行时。"}, {"t": "fill", "q": "\"过去某时正在进行\"用______时。", "a": ["过去进行", "进行"], "ex": "was/were doing。"}, {"t": "mc", "q": "has/have done 是哪种时态？", "opts": ["现在完成时", "一般过去时", "过去完成时", "将来完成时"], "a": 0, "ex": "现在完成时。"}, {"t": "tf", "q": "一般现在时可表示客观真理。", "a": true, "ex": "如 The earth moves。"}], "进阶": [{"t": "mc", "q": "\"by the time + 过去\"主句常用：", "opts": ["过去完成时", "一般现在时", "现在完成时", "一般将来时"], "a": 0, "ex": "过去的过去。"}, {"t": "mc", "q": "现在完成进行时强调：", "opts": ["瞬间结束", "将来动作", "从过去持续到现在且仍在进行", "客观真理"], "a": 2, "ex": "have been doing。"}, {"t": "tf", "q": "一般将来时可用 will do 或 be going to do。", "a": true, "ex": "两者皆可。"}, {"t": "fill", "q": "\"到将来某时将已完成\"用______时。", "a": ["将来完成", "完成"], "ex": "will have done。"}, {"t": "mc", "q": "He said he ______ come.（过去将来）", "opts": ["will", "would", "is going to", "shall"], "a": 1, "ex": "过去将来 would。"}, {"t": "translate", "q": "汉译英：太阳从东方升起。", "a": ["The sun rises in the east."], "ex": "客观真理用一般现在时。"}, {"t": "translate", "q": "汉译英：我昨天看了一部电影。", "a": ["I watched a film yesterday.", "I saw a movie yesterday."], "ex": "一般过去时。"}, {"t": "fill", "q": "判断时态：has been doing → ______进行时", "a": ["现在完成"], "ex": "现在完成进行时。"}, {"t": "mc", "q": "will have done 是哪种时态？", "opts": ["将来完成时", "将来进行时", "现在完成时", "过去完成时"], "a": 0, "ex": "将来完成时。"}, {"t": "tf", "q": "时间状语从句中常用一般现在时表将来。", "a": true, "ex": "主将从现。"}], "复习": [{"t": "mc", "q": "\"过去将来进行时\"的结构是：", "opts": ["will be doing", "would be doing", "was doing", "would do"], "a": 1, "ex": "would be doing。"}, {"t": "tf", "q": "现在完成时与明确过去时间状语连用。", "a": false, "ex": "不能连用，那种情况用一般过去时。"}, {"t": "fill", "q": "判断时态：had done → 过去______时", "a": ["完成"], "ex": "过去完成时。"}, {"t": "mc", "q": "表示\"将来某时正在进行\"用：", "opts": ["将来完成时", "将来进行时", "现在进行时", "过去进行时"], "a": 1, "ex": "will be doing。"}, {"t": "translate", "q": "汉译英：到明年这个时候我将已经毕业了。", "a": ["By this time next year, I will have graduated."], "ex": "将来完成时。"}, {"t": "translate", "q": "汉译英：我到那儿时电影已经开始了。", "a": ["When I got there, the film had already begun."], "ex": "过去完成时（过去的过去）。"}, {"t": "mc", "q": "\"动作持续到现在仍在进行\"用：", "opts": ["一般现在时", "一般过去时", "将来时", "现在完成进行时"], "a": 3, "ex": "have been doing。"}, {"t": "fill", "q": "判断时态：is being done → 现在进行时的______语态", "a": ["被动"], "ex": "现在进行时被动语态。"}, {"t": "mc", "q": "英语共有几种基本时态（时间×状态）？", "opts": ["8 种", "4 种", "16 种", "12 种"], "a": 2, "ex": "3 时间×... 通常归纳为 16 种时态体。"}, {"t": "tf", "q": "过去完成时表示\"过去的过去\"。", "a": true, "ex": "had done。"}]}, "ch13": {"入门": [{"t": "mc", "q": "The earth ______ around the sun.", "opts": ["move", "moved", "moves", "is moving"], "a": 2, "ex": "客观真理，第三人称单数。"}, {"t": "mc", "q": "I ______ to the park yesterday.", "opts": ["go", "goes", "went", "gone"], "a": 2, "ex": "yesterday 用一般过去时。"}, {"t": "tf", "q": "一般将来时可用 will + 动词原形。", "a": true, "ex": "will call。"}, {"t": "fill", "q": "用正确形式：He ______ (get) up at six every day.", "a": ["gets"], "ex": "习惯用一般现在时。"}, {"t": "mc", "q": "She ______ English every morning.", "opts": ["read", "reads", "reading", "is read"], "a": 1, "ex": "every morning 习惯，第三人称单数。"}, {"t": "tf", "q": "一般过去时的规则动词通常加 -ed。", "a": true, "ex": "如 work→worked。"}, {"t": "mc", "q": "We ______ a film last night.", "opts": ["watch", "watches", "watching", "watched"], "a": 3, "ex": "last night 用过去时。"}, {"t": "fill", "q": "用正确形式：Water ______ (boil) at 100℃.", "a": ["boils"], "ex": "客观真理。"}, {"t": "mc", "q": "Tomorrow I ______ visit my grandma.", "opts": ["am", "do", "did", "will"], "a": 3, "ex": "tomorrow 用一般将来时 will。"}, {"t": "tf", "q": "He don't like coffee. 该句正确。", "a": false, "ex": "主语 he 应用 doesn't。"}], "进阶": [{"t": "mc", "q": "Look at the clouds! It ______ rain.", "opts": ["is going to", "will", "shall", "would"], "a": 0, "ex": "有迹象用 be going to。"}, {"t": "fill", "q": "用正确形式：If it ______ (rain) tomorrow, we'll stay home.", "a": ["rains"], "ex": "主将从现。"}, {"t": "mc", "q": "He ______ to Beijing last week.", "opts": ["went", "goes", "has gone", "will go"], "a": 0, "ex": "last week 用过去时。"}, {"t": "fill", "q": "用正确形式：They ______ (not watch) TV last night.", "a": ["didn't watch", "did not watch"], "ex": "过去时否定 didn't + 原形。"}, {"t": "mc", "q": "The train ______ at 8:00 every day.", "opts": ["leave", "leaves", "left", "leaving"], "a": 1, "ex": "时刻表用一般现在时。"}, {"t": "translate", "q": "汉译英：他每天步行去上学。", "a": ["He goes to school on foot every day.", "He walks to school every day."], "ex": "习惯用一般现在时。"}, {"t": "translate", "q": "汉译英：我去年去了上海。", "a": ["I went to Shanghai last year."], "ex": "last year 用一般过去时。"}, {"t": "fill", "q": "用正确形式：______ you ______ (go) to the party tomorrow?", "a": ["going"], "ex": "be going to 表将来打算。"}, {"t": "mc", "q": "He ______ his homework every evening.", "opts": ["do", "did", "does", "doing"], "a": 2, "ex": "every evening 习惯，第三人称单数。"}, {"t": "tf", "q": "be going to 既可表打算，也可表有迹象的将来。", "a": true, "ex": "如 It's going to rain。"}], "复习": [{"t": "mc", "q": "He will leave when his father ______ back.", "opts": ["will come", "comes", "came", "is coming"], "a": 1, "ex": "时间从句用一般现在时。"}, {"t": "tf", "q": "He goes to school yesterday. 时态正确。", "a": false, "ex": "yesterday 应用 went。"}, {"t": "fill", "q": "用正确形式：The sun ______ (rise) in the east and ______ (set) in the west.", "a": ["rises; sets", "rises sets"], "ex": "客观真理，第三人称单数。"}, {"t": "mc", "q": "—Where is Tom? —He ______ to the library.", "opts": ["goes", "will go", "has gone", "go"], "a": 2, "ex": "已去图书馆（不在此），用现在完成时 has gone。"}, {"t": "translate", "q": "汉译英：如果明天下雨，我们就待在家里。", "a": ["If it rains tomorrow, we will stay at home."], "ex": "主将从现。"}, {"t": "translate", "q": "汉译英：水在零度结冰。", "a": ["Water freezes at zero degrees.", "Water freezes at 0℃."], "ex": "客观真理用一般现在时。"}, {"t": "mc", "q": "I'll tell him the news as soon as he ______.", "opts": ["will arrive", "arrived", "arrives", "is arriving"], "a": 2, "ex": "as soon as 从句用一般现在时表将来。"}, {"t": "fill", "q": "用正确形式：She ______ (not go) to school last Sunday.", "a": ["didn't go", "did not go"], "ex": "过去时否定。"}, {"t": "mc", "q": "My plane ______ at 9 a.m. tomorrow.", "opts": ["left", "leaves", "has left", "is leaving"], "a": 1, "ex": "时刻表安排可用一般现在时表将来。"}, {"t": "tf", "q": "\"主将从现\"指主句用将来时、从句用一般现在时。", "a": true, "ex": "时间/条件状语从句规则。"}]}, "ch14": {"入门": [{"t": "mc", "q": "Listen! Someone ______ at the door.", "opts": ["is knocking", "knocks", "knocked", "has knocked"], "a": 0, "ex": "Listen 提示现在进行时。"}, {"t": "tf", "q": "状态、情感动词（know, like）一般不用进行时。", "a": true, "ex": "静态动词。"}, {"t": "mc", "q": "They ______ football now.", "opts": ["play", "are playing", "plays", "played"], "a": 1, "ex": "now 用现在进行时。"}, {"t": "fill", "q": "用正确形式：The baby ______ (sleep) now.", "a": ["is sleeping"], "ex": "now 现在进行时。"}, {"t": "mc", "q": "Look! The bus ______.", "opts": ["comes", "came", "come", "is coming"], "a": 3, "ex": "Look! 现在进行时。"}, {"t": "tf", "q": "现在进行时结构是 am/is/are + 动词-ing。", "a": true, "ex": "be + doing。"}, {"t": "mc", "q": "She ______ a letter at the moment.", "opts": ["writes", "wrote", "is writing", "write"], "a": 2, "ex": "at the moment 现在进行时。"}, {"t": "fill", "q": "用正确形式：We ______ (have) a meeting now.", "a": ["are having"], "ex": "have\"开会\"可用进行时。"}, {"t": "mc", "q": "Don't make noise! The students ______ an exam.", "opts": ["take", "took", "are taking", "taken"], "a": 2, "ex": "此刻正在进行。"}, {"t": "tf", "q": "\"I am loving you.\" 是正确的。", "a": false, "ex": "love 静态动词，应为 I love you。"}], "进阶": [{"t": "mc", "q": "This time yesterday, I ______ a book.", "opts": ["read", "was reading", "am reading", "have read"], "a": 1, "ex": "this time yesterday 过去进行时。"}, {"t": "fill", "q": "用正确形式：They ______ (have) dinner when I called.", "a": ["were having"], "ex": "过去某时正在进行。"}, {"t": "mc", "q": "While she ______, the phone rang.", "opts": ["cooks", "was cooking", "cooked", "is cooking"], "a": 1, "ex": "while 从句过去进行时作背景。"}, {"t": "tf", "q": "I am knowing the answer. 正确。", "a": false, "ex": "know 不用进行时。"}, {"t": "mc", "q": "At eight last night, we ______ TV.", "opts": ["watch", "watched", "were watching", "are watching"], "a": 2, "ex": "过去某刻用过去进行时。"}, {"t": "translate", "q": "汉译英：他正在花园里浇花。", "a": ["He is watering the flowers in the garden."], "ex": "现在进行时。"}, {"t": "translate", "q": "汉译英：昨天我打电话时他正在睡觉。", "a": ["He was sleeping when I called yesterday.", "He was sleeping when I phoned yesterday."], "ex": "过去进行时 + when 从句。"}, {"t": "fill", "q": "用正确形式：What ______ you ______ (do) at nine last night?", "a": ["doing"], "ex": "过去进行时疑问。"}, {"t": "mc", "q": "He ______ to me when the teacher came in.", "opts": ["talks", "talked", "was talking", "has talked"], "a": 2, "ex": "过去某动作发生时正在进行。"}, {"t": "tf", "q": "现在进行时有时可表示\"已安排好的将来\"。", "a": true, "ex": "I am leaving tomorrow。"}], "复习": [{"t": "mc", "q": "This time next week, we ______ on the beach.", "opts": ["will be lying", "lie", "are lying", "lay"], "a": 0, "ex": "this time next week 将来进行时。"}, {"t": "fill", "q": "用正确形式：Don't disturb him; he ______ (write) a report.", "a": ["is writing"], "ex": "此刻正在进行。"}, {"t": "tf", "q": "将来进行时结构是 will be + 动词-ing。", "a": true, "ex": "will be doing。"}, {"t": "mc", "q": "While I ______ the room, my sister was cooking.", "opts": ["clean", "was cleaning", "cleaned", "am cleaning"], "a": 1, "ex": "两个过去动作同时进行，用过去进行时。"}, {"t": "translate", "q": "汉译英：明天这个时候我将在飞往北京的飞机上。", "a": ["At this time tomorrow, I will be flying to Beijing."], "ex": "将来进行时。"}, {"t": "translate", "q": "汉译英：当我进来时，他们正在讨论这个问题。", "a": ["When I came in, they were discussing the problem."], "ex": "过去进行时。"}, {"t": "mc", "q": "He always ______ others.（表抱怨）", "opts": ["helps", "is helping", "is always troubling", "troubles"], "a": 2, "ex": "always + 进行时表反复（含感情色彩）。"}, {"t": "fill", "q": "用正确形式：They ______ (build) a bridge this time last year.", "a": ["were building"], "ex": "过去进行时。"}, {"t": "mc", "q": "I ______ my homework from 7 to 9 last night.", "opts": ["did", "was doing", "do", "am doing"], "a": 1, "ex": "过去一段时间正在进行。"}, {"t": "tf", "q": "感官动词 see, hear 通常不用于进行时。", "a": true, "ex": "静态/感官动词。"}]}, "ch15": {"入门": [{"t": "mc", "q": "I ______ already ______ my homework.", "opts": ["have; finished", "has; finished", "am; finishing", "did; finish"], "a": 0, "ex": "already 现在完成时。"}, {"t": "tf", "q": "have been to 表\"去过\"，have gone to 表\"去了未回\"。", "a": true, "ex": "二者区别。"}, {"t": "mc", "q": "She ______ in this city for ten years.", "opts": ["lives", "has lived", "lived", "is living"], "a": 1, "ex": "for + 时间段，现在完成时。"}, {"t": "fill", "q": "用正确形式：______ you ever ______ (be) to Beijing?", "a": ["been"], "ex": "ever 现在完成时。"}, {"t": "mc", "q": "I ______ my key. I can't find it.", "opts": ["lose", "have lost", "lost", "am losing"], "a": 1, "ex": "对现在有影响，现在完成时。"}, {"t": "tf", "q": "现在完成时结构是 have/has + 过去分词。", "a": true, "ex": "have done。"}, {"t": "mc", "q": "He ______ just ______ .", "opts": ["have; arrived", "is; arriving", "has; arrived", "did; arrive"], "a": 2, "ex": "just 现在完成时，主语 he 用 has。"}, {"t": "fill", "q": "用正确形式：They ______ (not finish) the work yet.", "a": ["haven't finished", "have not finished"], "ex": "yet 用于现在完成时否定。"}, {"t": "mc", "q": "I have known him ______ 2010.", "opts": ["for", "in", "since", "at"], "a": 2, "ex": "since + 时间点。"}, {"t": "tf", "q": "already 常用于肯定句，yet 常用于否定句和疑问句。", "a": true, "ex": "现在完成时标志词。"}], "进阶": [{"t": "mc", "q": "He ______ to Shanghai; he isn't here now.", "opts": ["has been", "has gone", "went", "goes"], "a": 1, "ex": "去了未回，has gone。"}, {"t": "fill", "q": "用正确形式：They ______ (know) each other since 2010.", "a": ["have known"], "ex": "since + 时间点，延续动词。"}, {"t": "mc", "q": "How long ______ you ______ this book?", "opts": ["have; had", "did; have", "do; have", "are; having"], "a": 0, "ex": "how long + 延续动词 + 现在完成时。"}, {"t": "tf", "q": "现在完成时可与 yesterday 连用。", "a": false, "ex": "不能与明确过去时间状语连用。"}, {"t": "mc", "q": "—Have you finished? —Yes, I ______.", "opts": ["do", "did", "have", "am"], "a": 2, "ex": "现在完成时简略回答用 have。"}, {"t": "translate", "q": "汉译英：他已经去过北京三次了。", "a": ["He has been to Beijing three times."], "ex": "have been to + 次数。"}, {"t": "translate", "q": "汉译英：我们已经认识十年了。", "a": ["We have known each other for ten years."], "ex": "for + 时间段 + 延续动词。"}, {"t": "fill", "q": "用正确形式：The film ______ (begin) already.", "a": ["has begun"], "ex": "already 现在完成时。"}, {"t": "mc", "q": "I ______ this book and you can read it now.", "opts": ["read", "am reading", "have read", "will read"], "a": 2, "ex": "对现在有影响（读完了），现在完成时。"}, {"t": "tf", "q": "\"have been to\" 后可接 times 表示去过的次数。", "a": true, "ex": "如 been to ... twice。"}], "复习": [{"t": "mc", "q": "现在完成进行时正确的一项：", "opts": ["I have waited here.", "I am waiting.", "I waited.", "I have been waiting here for an hour."], "a": 3, "ex": "have been doing 强调持续。"}, {"t": "fill", "q": "用正确形式：The rain ______ (stop); the sun is out now.", "a": ["has stopped"], "ex": "对现在结果有影响。"}, {"t": "mc", "q": "延续表达：He ______ the club for two years.", "opts": ["has joined", "has been a member of", "joined", "joins"], "a": 1, "ex": "join 短暂动词，改 be a member of。"}, {"t": "tf", "q": "短暂性动词不能直接与\"for+时间段\"连用。", "a": true, "ex": "如 die→be dead。"}, {"t": "translate", "q": "汉译英：自从那以后我再也没见过他。", "a": ["I haven't seen him since then.", "I have never seen him since then."], "ex": "since + 完成时。"}, {"t": "translate", "q": "汉译英：你做这项工作多久了？", "a": ["How long have you done this work?", "How long have you been doing this job?"], "ex": "how long + 完成时/完成进行时。"}, {"t": "mc", "q": "He ______ his grandparents for two years.", "opts": ["didn't see", "doesn't see", "won't see", "hasn't seen"], "a": 3, "ex": "for + 时间段 + 现在完成时。"}, {"t": "fill", "q": "用延续动词改写：His grandpa ______ (die) for three years.（用 be dead）", "a": ["has been dead"], "ex": "die→be dead 才能接时间段。"}, {"t": "mc", "q": "They have been married ______ five years.", "opts": ["since", "for", "in", "ago"], "a": 1, "ex": "be married 延续状态 + for。"}, {"t": "tf", "q": "现在完成进行时 = have/has been + 动词-ing。", "a": true, "ex": "强调动作持续到现在。"}]}, "ch16": {"入门": [{"t": "mc", "q": "When I arrived, the train ______ already ______.", "opts": ["has; left", "was; leaving", "had; left", "did; leave"], "a": 2, "ex": "过去的过去用过去完成时。"}, {"t": "tf", "q": "过去完成时表示\"过去某时之前已完成\"。", "a": true, "ex": "过去的过去。"}, {"t": "mc", "q": "By the end of last term, we ______ 1000 words.", "opts": ["had learned", "learn", "learned", "have learned"], "a": 0, "ex": "by + 过去时间，过去完成时。"}, {"t": "fill", "q": "用正确形式：She said she ______ (finish) the book.", "a": ["had finished"], "ex": "主句过去，从句更早用过去完成时。"}, {"t": "mc", "q": "过去完成时的结构是：", "opts": ["was/were doing", "have done", "had + 过去分词", "will have done"], "a": 2, "ex": "had + 过去分词。"}, {"t": "tf", "q": "将来完成时结构是 will + have + 过去分词。", "a": true, "ex": "will have done。"}, {"t": "mc", "q": "By next month, I ______ here for three years.", "opts": ["will have worked", "will work", "have worked", "worked"], "a": 0, "ex": "by + 将来时间，将来完成时。"}, {"t": "fill", "q": "用正确形式：He told me he ______ (post) the letter.", "a": ["had posted"], "ex": "过去的过去。"}, {"t": "mc", "q": "After he ______ his work, he went home.", "opts": ["had finished", "finished", "has finished", "finishes"], "a": 0, "ex": "after 从句更早，用过去完成时。"}, {"t": "tf", "q": "\"by + 过去时间点\"常与过去完成时连用。", "a": true, "ex": "by the end of...。"}], "进阶": [{"t": "mc", "q": "They ______ the project by the time you come back.", "opts": ["finish", "will finish", "have finished", "will have finished"], "a": 3, "ex": "by the time + 将来，将来完成时。"}, {"t": "fill", "q": "用正确形式：I ______ (not see) him before yesterday.", "a": ["had not seen", "hadn't seen"], "ex": "before yesterday 过去完成时。"}, {"t": "mc", "q": "He ______ the letter the day before.", "opts": ["posts", "had posted", "posted", "has posted"], "a": 1, "ex": "the day before 过去的过去。"}, {"t": "tf", "q": "no sooner...than 常与过去完成时连用。", "a": true, "ex": "had no sooner...than...。"}, {"t": "mc", "q": "By 2030, the city ______ ten new schools.", "opts": ["will build", "has built", "will have built", "built"], "a": 2, "ex": "by + 将来时间，将来完成时。"}, {"t": "translate", "q": "汉译英：我到达车站时火车已经开走了。", "a": ["When I got to the station, the train had already left."], "ex": "过去完成时。"}, {"t": "translate", "q": "汉译英：到下周末我将已经读完这本书。", "a": ["By the end of next week, I will have finished the book."], "ex": "将来完成时。"}, {"t": "fill", "q": "用正确形式：By last year, he ______ (work) here for ten years.", "a": ["had worked"], "ex": "by + 过去时间，过去完成时。"}, {"t": "mc", "q": "Hardly ______ when it began to rain.", "opts": ["he had arrived", "he arrived", "had he arrived", "did he arrive"], "a": 2, "ex": "Hardly 置句首部分倒装 + 过去完成时。"}, {"t": "tf", "q": "过去完成时常用于宾语从句表示\"更早发生\"。", "a": true, "ex": "He said he had done it。"}], "复习": [{"t": "mc", "q": "After they ______ supper, they watched TV.", "opts": ["had had", "have had", "have", "having"], "a": 0, "ex": "过去完成时（更早动作）。"}, {"t": "fill", "q": "用正确形式：By the time the police came, the thief ______ (run) away.", "a": ["had run"], "ex": "过去的过去。"}, {"t": "tf", "q": "将来完成时常与 by + 将来时间点连用。", "a": true, "ex": "by next year。"}, {"t": "mc", "q": "I ______ the film before, so I didn't watch it again.", "opts": ["have seen", "saw", "had seen", "see"], "a": 2, "ex": "过去的过去用过去完成时。"}, {"t": "translate", "q": "汉译英：他说他以前从没去过那里。", "a": ["He said he had never been there before."], "ex": "宾语从句过去完成时。"}, {"t": "translate", "q": "汉译英：到他回来时我们将已经吃完饭了。", "a": ["By the time he comes back, we will have finished dinner."], "ex": "将来完成时 + 时间从句一般现在时。"}, {"t": "mc", "q": "She realized she ______ her keys at home.", "opts": ["leaves", "left", "had left", "has left"], "a": 2, "ex": "意识到之前已落下，用过去完成时。"}, {"t": "fill", "q": "用正确形式：No sooner had he sat down than the phone ______ (ring).", "a": ["rang"], "ex": "no sooner had...than + 一般过去时。"}, {"t": "mc", "q": "By the time I am 30, I ______ my own company.", "opts": ["will start", "have started", "started", "will have started"], "a": 3, "ex": "将来完成时。"}, {"t": "tf", "q": "\"过去的过去\"用过去完成时，\"将来的完成\"用将来完成时。", "a": true, "ex": "had done / will have done。"}]}, "ch17": {"入门": [{"t": "mc", "q": "English ______ in many countries.", "opts": ["speaks", "spoke", "is spoken", "speaking"], "a": 2, "ex": "一般现在时被动 is spoken。"}, {"t": "tf", "q": "被动语态结构是 be + 及物动词的过去分词。", "a": true, "ex": "be done。"}, {"t": "mc", "q": "The window ______ by Tom yesterday.", "opts": ["broke", "was broken", "is broken", "breaks"], "a": 1, "ex": "过去时被动 was broken。"}, {"t": "fill", "q": "变被动：They clean the room every day. → The room ______ ______ every day.", "a": ["is cleaned"], "ex": "一般现在时被动。"}, {"t": "mc", "q": "The book ______ by many students.", "opts": ["reads", "is read", "reading", "read"], "a": 1, "ex": "被读，一般现在时被动。"}, {"t": "tf", "q": "主动 \"They built the bridge.\" 的被动是 \"The bridge was built.\"", "a": true, "ex": "过去时被动。"}, {"t": "mc", "q": "Rice ______ in the south of China.", "opts": ["grows", "grew", "is grown", "growing"], "a": 2, "ex": "被种植，被动语态。"}, {"t": "fill", "q": "变被动：He writes the letter. → The letter ______ ______ by him.", "a": ["is written"], "ex": "一般现在时被动。"}, {"t": "mc", "q": "These cars ______ in Germany.", "opts": ["make", "makes", "making", "are made"], "a": 3, "ex": "被制造，被动语态。"}, {"t": "tf", "q": "被动语态强调动作的承受者。", "a": true, "ex": "承受者作主语。"}], "进阶": [{"t": "mc", "q": "A new bridge ______ in our city now.", "opts": ["is building", "is being built", "is built", "builds"], "a": 1, "ex": "现在进行时被动 is being built。"}, {"t": "mc", "q": "The work ______ before next week.", "opts": ["must finish", "must finishes", "must be finished", "must finishing"], "a": 2, "ex": "情态动词被动 must be done。"}, {"t": "fill", "q": "变被动：Someone has cleaned the room. → The room ______ ______ ______.", "a": ["has been cleaned"], "ex": "现在完成时被动。"}, {"t": "mc", "q": "The medicine ______ in a cool place.", "opts": ["should keep", "should be kept", "should keeps", "keeps"], "a": 1, "ex": "情态动词被动。"}, {"t": "mc", "q": "The house ______ when I arrived.", "opts": ["was painting", "painted", "is painted", "was being painted"], "a": 3, "ex": "过去进行时被动。"}, {"t": "translate", "q": "汉译英：这座桥是去年建成的。", "a": ["The bridge was built last year."], "ex": "过去时被动。"}, {"t": "translate", "q": "汉译英：英语在世界各地被使用。", "a": ["English is used all over the world.", "English is spoken all over the world."], "ex": "一般现在时被动。"}, {"t": "fill", "q": "变被动：They will hold a meeting. → A meeting ______ ______ ______.", "a": ["will be held"], "ex": "将来时被动。"}, {"t": "mc", "q": "The homework must ______ before class.", "opts": ["finish", "be finished", "finished", "being finished"], "a": 1, "ex": "must be + 过去分词。"}, {"t": "tf", "q": "含情态动词的被动是\"情态动词 + be + 过去分词\"。", "a": true, "ex": "如 can be done。"}], "复习": [{"t": "mc", "q": "He ______ to give a speech at the meeting.", "opts": ["asked", "asks", "is asking", "was asked"], "a": 3, "ex": "被要求，被动语态。"}, {"t": "tf", "q": "不及物动词没有被动语态。", "a": true, "ex": "只有及物动词有被动。"}, {"t": "fill", "q": "变被动：People will build a school here. → A school ______ ______ ______ here.", "a": ["will be built"], "ex": "将来时被动。"}, {"t": "mc", "q": "I ______ to the party by Mary.", "opts": ["invited", "invite", "was invited", "am inviting"], "a": 2, "ex": "被邀请。"}, {"t": "translate", "q": "汉译英：这个问题必须马上解决。", "a": ["This problem must be solved at once.", "The problem must be settled right now."], "ex": "情态动词被动。"}, {"t": "translate", "q": "汉译英：一所新医院正在建造中。", "a": ["A new hospital is being built."], "ex": "现在进行时被动。"}, {"t": "mc", "q": "The flowers need ______ every day.", "opts": ["water", "to water", "watered", "watering"], "a": 3, "ex": "need doing = need to be done（被动含义）。"}, {"t": "fill", "q": "变被动：They are repairing the road. → The road ______ ______ ______.", "a": ["is being repaired"], "ex": "现在进行时被动。"}, {"t": "mc", "q": "He was made ______ harder by his teacher.", "opts": ["work", "working", "to work", "worked"], "a": 2, "ex": "make 的被动中省略的 to 要还原。"}, {"t": "tf", "q": "\"by + 动作执行者\"在被动句中可省略。", "a": true, "ex": "不重要或不知时可省略。"}]}, "ch18": {"入门": [{"t": "mc", "q": "There ______ a book on the desk.", "opts": ["is", "are", "have", "has"], "a": 0, "ex": "a book 单数用 is。"}, {"t": "tf", "q": "There be 句型表示\"某处存在某物\"。", "a": true, "ex": "there 无实义。"}, {"t": "mc", "q": "There ______ many students in the classroom.", "opts": ["is", "has", "have", "are"], "a": 3, "ex": "many students 复数用 are。"}, {"t": "fill", "q": "用 be：There ______ some water in the bottle.", "a": ["is"], "ex": "water 不可数用 is。"}, {"t": "mc", "q": "There ______ a cat under the table.", "opts": ["are", "is", "have", "has"], "a": 1, "ex": "a cat 单数。"}, {"t": "tf", "q": "There have a book on the desk. 该句正确。", "a": false, "ex": "应为 There is a book（不用 have）。"}, {"t": "mc", "q": "There ______ four seasons in a year.", "opts": ["are", "is", "has", "have"], "a": 0, "ex": "four seasons 复数。"}, {"t": "fill", "q": "用 be：There ______ an apple and two pears.", "a": ["is"], "ex": "就近原则，与 an apple 一致。"}, {"t": "mc", "q": "How many books ______ there on the shelf?", "opts": ["is", "are", "has", "have"], "a": 1, "ex": "books 复数用 are。"}, {"t": "tf", "q": "There be 句型中 be 与其后第一个主语保持一致。", "a": true, "ex": "就近原则。"}], "进阶": [{"t": "mc", "q": "There ______ a pen and two books on the table.", "opts": ["are", "is", "have", "has"], "a": 1, "ex": "就近原则，与 a pen 一致。"}, {"t": "mc", "q": "There ______ a meeting tomorrow.", "opts": ["is going to have", "will have", "has", "is going to be"], "a": 3, "ex": "There is going to be / will be。"}, {"t": "fill", "q": "用 be：There ______ two apples and an orange in the bag.", "a": ["are"], "ex": "就近原则，与 two apples 一致。"}, {"t": "mc", "q": "There ______ no one in the room just now.", "opts": ["was", "is", "are", "were"], "a": 0, "ex": "just now 过去，no one 单数用 was。"}, {"t": "mc", "q": "There ______ a lot of rain last summer.", "opts": ["is", "were", "had", "was"], "a": 3, "ex": "rain 不可数 + 过去，用 was。"}, {"t": "translate", "q": "汉译英：桌子上有一本书和两支笔。", "a": ["There is a book and two pens on the desk."], "ex": "就近原则，与 a book 一致用 is。"}, {"t": "translate", "q": "汉译英：明天将有一场足球比赛。", "a": ["There is going to be a football match tomorrow.", "There will be a football match tomorrow."], "ex": "There be 将来时。"}, {"t": "fill", "q": "用 be：There ______ (过去) many people at the party.", "a": ["were"], "ex": "many people 复数过去用 were。"}, {"t": "mc", "q": "There ______ going to be a test next week.", "opts": ["are", "has", "have", "is"], "a": 3, "ex": "There is going to be。"}, {"t": "tf", "q": "There seems to be a problem. 该结构正确。", "a": true, "ex": "There seems/happens to be 也是存在句变体。"}], "复习": [{"t": "mc", "q": "There ______ little change since then.", "opts": ["is", "has been", "have been", "was"], "a": 1, "ex": "There has been（现在完成时），change 不可数。"}, {"t": "tf", "q": "There has been little rain this year. 正确。", "a": true, "ex": "There be 现在完成时。"}, {"t": "fill", "q": "用 be：There ______ going to be a sports meeting next week.", "a": ["is"], "ex": "There is going to be。"}, {"t": "mc", "q": "How many people ______ there in your family?", "opts": ["is", "has", "have", "are"], "a": 3, "ex": "people 复数用 are。"}, {"t": "translate", "q": "汉译英：自从那时起这里发生了很大变化。", "a": ["There has been a great change here since then.", "There have been great changes here since then."], "ex": "There be 现在完成时。"}, {"t": "translate", "q": "汉译英：瓶子里没有水了。", "a": ["There is no water in the bottle.", "There isn't any water in the bottle."], "ex": "water 不可数用 is。"}, {"t": "mc", "q": "There used ______ a temple on the hill.", "opts": ["to be", "to have", "being", "be"], "a": 0, "ex": "there used to be 过去曾经有。"}, {"t": "fill", "q": "用 be：There ______ (现在完成) been three accidents this week.", "a": ["have"], "ex": "three accidents 复数，现在完成时 have been。"}, {"t": "mc", "q": "There ______ to be a school here, but it's gone now.", "opts": ["used", "use", "using", "uses"], "a": 0, "ex": "there used to be。"}, {"t": "tf", "q": "There be 句型的反意疑问句用 ...isn't there? 等形式。", "a": true, "ex": "反意疑问句仍用 there。"}]}, "ch19": {"入门": [{"t": "mc", "q": "I don't know ______ he will come.", "opts": ["that", "what", "whether", "which"], "a": 2, "ex": "宾语从句表\"是否\"用 whether/if。"}, {"t": "tf", "q": "名词性从句一律用陈述语序。", "a": true, "ex": "连接词+主语+谓语。"}, {"t": "mc", "q": "______ he said is true.", "opts": ["What", "That", "Whether", "If"], "a": 0, "ex": "主语从句缺主语用 what。"}, {"t": "fill", "q": "填引导词：Tell me ______ you live.（你住哪儿）", "a": ["where"], "ex": "缺地点状语用 where。"}, {"t": "mc", "q": "I think ______ he is right.", "opts": ["what", "whether", "which", "that"], "a": 3, "ex": "宾语从句不缺成分用 that（可省略）。"}, {"t": "tf", "q": "宾语从句中的 that 有时可以省略。", "a": true, "ex": "如 I think (that) he is right。"}, {"t": "mc", "q": "Do you know ______ the meeting will begin?", "opts": ["that", "what", "which", "when"], "a": 3, "ex": "缺时间状语用 when。"}, {"t": "fill", "q": "填引导词：I wonder ______ he will agree or not.", "a": ["whether"], "ex": "\"...or not\" 用 whether。"}, {"t": "mc", "q": "The question is ______ we can win.", "opts": ["that", "whether", "what", "which"], "a": 1, "ex": "表语从句表\"是否\"用 whether。"}, {"t": "tf", "q": "if 一般不引导主语从句和表语从句。", "a": true, "ex": "主语/表语从句表\"是否\"用 whether。"}], "进阶": [{"t": "mc", "q": "______ he will come is still unknown.", "opts": ["That", "If", "What", "Whether"], "a": 3, "ex": "主语从句表\"是否\"用 whether。"}, {"t": "mc", "q": "The problem is ______ we can finish it on time.", "opts": ["that", "what", "whether", "which"], "a": 2, "ex": "表语从句表\"是否\"。"}, {"t": "fill", "q": "填引导词：The fact ______ he lied surprised us.", "a": ["that"], "ex": "同位语从句不缺成分用 that。"}, {"t": "mc", "q": "It is important ______ we should study hard.", "opts": ["what", "whether", "that", "which"], "a": 2, "ex": "形式主语 it，从句不缺成分用 that。"}, {"t": "mc", "q": "______ surprised me was that he passed.", "opts": ["That", "Which", "It", "What"], "a": 3, "ex": "主语从句缺主语用 what。"}, {"t": "translate", "q": "汉译英：我不知道他是否会来。", "a": ["I don't know whether he will come.", "I don't know if he will come."], "ex": "宾语从句表\"是否\"用 whether/if。"}, {"t": "translate", "q": "汉译英：他所说的话使我们很吃惊。", "a": ["What he said surprised us."], "ex": "主语从句用 what（从句中作宾语）。"}, {"t": "fill", "q": "填引导词：I have no idea ______ to do next.", "a": ["what"], "ex": "连接词+不定式，缺宾语用 what。"}, {"t": "mc", "q": "He asked me ______ I had finished the work.", "opts": ["that", "what", "if", "which"], "a": 2, "ex": "宾语从句表\"是否\"用 if/whether。"}, {"t": "tf", "q": "宾语从句的时态要与主句呼应（主过去从用过去相关时态）。", "a": true, "ex": "时态呼应原则。"}], "复习": [{"t": "mc", "q": "I suggested that he ______ to the doctor at once.", "opts": ["go", "goes", "went", "will go"], "a": 0, "ex": "suggest 后从句虚拟 (should) go。"}, {"t": "tf", "q": "\"一坚持二命令三建议四要求\"类动词后从句用虚拟语气。", "a": true, "ex": "(should) + 动词原形。"}, {"t": "fill", "q": "填引导词：______ we need is more time.", "a": ["What"], "ex": "主语从句缺主语用 what。"}, {"t": "mc", "q": "The doctor insisted that he ______ in bed.", "opts": ["stays", "stayed", "stay", "will stay"], "a": 2, "ex": "insist（坚持要求）后用虚拟语气。"}, {"t": "translate", "q": "汉译英：问题是我们能否按时完成。", "a": ["The question is whether we can finish it on time."], "ex": "表语从句用 whether。"}, {"t": "translate", "q": "汉译英：老师建议我们多读英语。", "a": ["The teacher suggested that we (should) read more English."], "ex": "suggest 后虚拟语气。"}, {"t": "mc", "q": "It is necessary that we ______ the rules.", "opts": ["obeys", "obeyed", "obey", "will obey"], "a": 2, "ex": "It is necessary that... 从句用虚拟 (should) obey。"}, {"t": "fill", "q": "填引导词：This is ______ I want to tell you.", "a": ["what"], "ex": "表语从句缺宾语用 what。"}, {"t": "mc", "q": "He made it clear ______ he disagreed.", "opts": ["what", "whether", "which", "that"], "a": 3, "ex": "it 形式宾语，that 引导真正宾语从句。"}, {"t": "tf", "q": "\"It is suggested that...\" 后的从句也用虚拟语气。", "a": true, "ex": "(should) + 动词原形。"}]}, "ch20": {"入门": [{"t": "mc", "q": "The man ______ is talking is my teacher.", "opts": ["who", "which", "whom", "whose"], "a": 0, "ex": "指人作主语用 who。"}, {"t": "tf", "q": "限制性定语从句中作宾语的关系代词可省略。", "a": true, "ex": "the book (that) I bought。"}, {"t": "mc", "q": "This is the book ______ I bought yesterday.", "opts": ["who", "which", "whose", "where"], "a": 1, "ex": "指物作宾语用 which/that。"}, {"t": "fill", "q": "填关系词：I know the reason ______ he was late.", "a": ["why"], "ex": "reason 作原因状语用 why。"}, {"t": "mc", "q": "The girl ______ hair is long is Lily.", "opts": ["who", "whose", "which", "whom"], "a": 1, "ex": "表所属用 whose。"}, {"t": "tf", "q": "关系代词 who 指人，which 指物。", "a": true, "ex": "基本用法。"}, {"t": "mc", "q": "The house ______ we live in is old.", "opts": ["which", "who", "whose", "where"], "a": 0, "ex": "in 的宾语，用 which（也可 that）。"}, {"t": "fill", "q": "填关系词：The students ______ passed the exam are happy.", "a": ["who", "that"], "ex": "指人作主语用 who/that。"}, {"t": "mc", "q": "This is the city ______ I was born.", "opts": ["which", "where", "that", "who"], "a": 1, "ex": "作地点状语用 where。"}, {"t": "tf", "q": "先行词指物且在从句中作主语时可用 which 或 that。", "a": true, "ex": "which/that 皆可。"}], "进阶": [{"t": "mc", "q": "This is the house ______ we lived last year.", "opts": ["where", "which", "that", "who"], "a": 0, "ex": "作地点状语用 where。"}, {"t": "mc", "q": "I remember the day ______ I met her.", "opts": ["which", "when", "that", "where"], "a": 1, "ex": "作时间状语用 when。"}, {"t": "fill", "q": "填关系词：The girl ______ bag was stolen is crying.", "a": ["whose"], "ex": "表所属用 whose。"}, {"t": "mc", "q": "Is there anything ______ I can do for you?", "opts": ["who", "which", "that", "what"], "a": 2, "ex": "先行词 anything 用 that。"}, {"t": "mc", "q": "This is the very book ______ I want.", "opts": ["who", "that", "which", "what"], "a": 1, "ex": "the very + 先行词，用 that。"}, {"t": "translate", "q": "汉译英：这就是我昨天买的那本书。", "a": ["This is the book (that) I bought yesterday.", "This is the book which I bought yesterday."], "ex": "指物作宾语用 that/which（可省略）。"}, {"t": "translate", "q": "汉译英：站在门口的那个男孩是我弟弟。", "a": ["The boy who is standing at the door is my brother.", "The boy standing at the door is my brother."], "ex": "指人作主语用 who。"}, {"t": "fill", "q": "填关系词：The reason ______ he gave is not true.", "a": ["that", "which"], "ex": "gave 的宾语用 that/which（非作状语，不用 why）。"}, {"t": "mc", "q": "He is the only person ______ can help.", "opts": ["who", "that", "which", "whom"], "a": 1, "ex": "先行词被 the only 修饰用 that。"}, {"t": "tf", "q": "先行词被 the only/the very/序数词修饰时，关系词常用 that。", "a": true, "ex": "that 优先。"}], "复习": [{"t": "mc", "q": "Beijing, ______ is the capital of China, has a long history.", "opts": ["that", "where", "which", "it"], "a": 2, "ex": "非限制性从句指物用 which。"}, {"t": "mc", "q": "He has two sons, both of ______ are doctors.", "opts": ["them", "whom", "who", "which"], "a": 1, "ex": "数词+of+whom 指人。"}, {"t": "fill", "q": "填关系词：The way ______ he speaks is strange.", "a": ["that", "in which"], "ex": "the way 后用 that/in which 或不填。"}, {"t": "tf", "q": "非限制性定语从句不能用 that 引导。", "a": true, "ex": "用 which/who 等。"}, {"t": "translate", "q": "汉译英：他通过了考试，这使我们很高兴。", "a": ["He passed the exam, which made us happy."], "ex": "which 指代整个主句。"}, {"t": "translate", "q": "汉译英：我永远不会忘记我们初次见面的那一天。", "a": ["I will never forget the day when we first met.", "I'll never forget the day on which we first met."], "ex": "day 作时间状语用 when/on which。"}, {"t": "mc", "q": "The teacher praised the students, most of ______ were hard-working.", "opts": ["whom", "them", "who", "which"], "a": 0, "ex": "most of whom 指人。"}, {"t": "fill", "q": "填关系词：Water, ______ covers most of the earth, is precious.", "a": ["which"], "ex": "非限制性从句指物用 which。"}, {"t": "mc", "q": "Such ______ I saw left a deep impression.", "opts": ["that", "which", "what", "as"], "a": 3, "ex": "such...as... 固定搭配，as 引导定语从句。"}, {"t": "tf", "q": "关系副词 when/where/why 在从句中作状语。", "a": true, "ex": "分别表时间/地点/原因状语。"}]}, "ch21": {"入门": [{"t": "mc", "q": "I'll call you ______ I arrive.", "opts": ["while", "since", "as soon as", "though"], "a": 2, "ex": "as soon as 一……就……。"}, {"t": "tf", "q": "时间和条件状语从句中常用一般现在时表将来。", "a": true, "ex": "主将从现。"}, {"t": "mc", "q": "______ it was raining, they went out.", "opts": ["Because", "If", "As", "Although"], "a": 3, "ex": "Although 让步。"}, {"t": "fill", "q": "填连词：______ you hurry, you'll be late.（除非）", "a": ["Unless"], "ex": "Unless = if...not。"}, {"t": "mc", "q": "He stayed at home ______ it was raining.", "opts": ["although", "because", "if", "while"], "a": 1, "ex": "because 原因。"}, {"t": "tf", "q": "when, while, as 都可引导时间状语从句。", "a": true, "ex": "表\"当……时\"。"}, {"t": "mc", "q": "I'll wait ______ you come back.", "opts": ["unless", "although", "until", "because"], "a": 2, "ex": "until 直到。"}, {"t": "fill", "q": "填连词：______ (如果) it rains, we'll stay home.", "a": ["If"], "ex": "If 引导条件从句。"}, {"t": "mc", "q": "______ I was young, I lived in the country.", "opts": ["Because", "Although", "When", "Unless"], "a": 2, "ex": "When 表时间。"}, {"t": "tf", "q": "so that 可引导目的状语从句。", "a": true, "ex": "so that 以便。"}], "进阶": [{"t": "mc", "q": "He spoke loudly ______ everyone could hear him.", "opts": ["such that", "in order", "because", "so that"], "a": 3, "ex": "so that 目的从句。"}, {"t": "mc", "q": "He was ______ tired ______ he fell asleep.", "opts": ["so; that", "such; that", "too; to", "very; that"], "a": 0, "ex": "so+形容词+that 结果从句。"}, {"t": "fill", "q": "填连词：______ he is young, he can't do this.（既然）", "a": ["Since", "As", "Because"], "ex": "原因从句。"}, {"t": "mc", "q": "______ hard he tried, he failed.", "opts": ["However", "Whatever", "No matter", "Although"], "a": 0, "ex": "However + 副词，让步。"}, {"t": "mc", "q": "It was ______ a cold day ______ we stayed inside.", "opts": ["so; that", "too; to", "such; that", "very; that"], "a": 2, "ex": "such + a + 形容词 + 名词 + that。"}, {"t": "translate", "q": "汉译英：他一到家就开始做作业。", "a": ["He started doing his homework as soon as he got home.", "As soon as he got home, he began his homework."], "ex": "as soon as 时间从句。"}, {"t": "translate", "q": "汉译英：尽管下着雨，他们还是踢足球了。", "a": ["Although it was raining, they still played football.", "They played football although it was raining."], "ex": "although 让步从句。"}, {"t": "fill", "q": "填连词：He works hard ______ (以便) he can pass the exam.", "a": ["so that"], "ex": "目的状语从句。"}, {"t": "mc", "q": "You won't pass ______ you study harder.", "opts": ["if", "because", "although", "unless"], "a": 3, "ex": "unless 除非。"}, {"t": "tf", "q": "so...that 与 such...that 都可引导结果状语从句。", "a": true, "ex": "so 接形容词/副词，such 接名词。"}], "复习": [{"t": "mc", "q": "If I ______ you, I would accept it.（与现在相反）", "opts": ["am", "was", "be", "were"], "a": 3, "ex": "虚拟语气 be 用 were。"}, {"t": "mc", "q": "If he ______ harder, he would have passed.（与过去相反）", "opts": ["worked", "works", "had worked", "has worked"], "a": 2, "ex": "与过去相反用 had + 过去分词。"}, {"t": "fill", "q": "虚拟语气：I wish I ______ (can) fly.", "a": ["could"], "ex": "wish 后与现在相反用过去式/could。"}, {"t": "tf", "q": "与将来相反的虚拟，主句常用 would/should + 动词原形。", "a": true, "ex": "如 If it should rain...。"}, {"t": "translate", "q": "汉译英：如果我是你，我就会接受这份工作。", "a": ["If I were you, I would accept the job.", "If I were you, I would take the job."], "ex": "与现在相反的虚拟语气，were + would。"}, {"t": "translate", "q": "汉译英：要不是你的帮助，我就失败了。", "a": ["But for your help, I would have failed.", "Without your help, I would have failed."], "ex": "含蓄条件，与过去相反。"}, {"t": "mc", "q": "He talks ______ he knew everything.", "opts": ["even if", "so that", "as if", "now that"], "a": 2, "ex": "as if 引导方式从句，常用虚拟语气。"}, {"t": "fill", "q": "虚拟语气：If he ______ (be) here now, he would help us.", "a": ["were"], "ex": "与现在相反用 were。"}, {"t": "mc", "q": "______ you study hard, you will succeed.", "opts": ["Even though", "As long as", "In case", "No matter"], "a": 1, "ex": "As long as 只要（条件）。"}, {"t": "tf", "q": "与现在事实相反的虚拟条件句，从句用一般过去时。", "a": true, "ex": "主句 would + 动词原形。"}]}, "ch22": {"入门": [{"t": "mc", "q": "强调句\"It is...that...\"强调人时 that 可换成：", "opts": ["which", "where", "who", "when"], "a": 2, "ex": "强调人用 who。"}, {"t": "tf", "q": "感叹句可由 What 或 How 引导。", "a": true, "ex": "What 修饰名词，How 修饰形容词/副词。"}, {"t": "mc", "q": "______ a beautiful flower it is!", "opts": ["How", "Such", "Very", "What"], "a": 3, "ex": "What a + 形容词 + 名词。"}, {"t": "fill", "q": "改感叹句：The boy is very clever. → ______ clever the boy is!", "a": ["How"], "ex": "感叹形容词用 How。"}, {"t": "mc", "q": "______ fast he runs!", "opts": ["What", "Such", "How", "Very"], "a": 2, "ex": "感叹副词 fast 用 How。"}, {"t": "tf", "q": "Here comes the bus. 是完全倒装句。", "a": true, "ex": "Here + 动词 + 名词主语。"}, {"t": "mc", "q": "______ interesting books they are!", "opts": ["What", "How", "What a", "How a"], "a": 0, "ex": "感叹复数名词用 What（不加 a）。"}, {"t": "fill", "q": "用 It is...that... 强调：It is Tom ______ broke the window.", "a": ["that", "who"], "ex": "强调人用 that/who。"}, {"t": "mc", "q": "Never ______ such a thing.", "opts": ["I have seen", "have I seen", "I saw", "saw I"], "a": 1, "ex": "否定词置句首部分倒装。"}, {"t": "tf", "q": "What 引导感叹句时修饰名词，How 修饰形容词或副词。", "a": true, "ex": "基本区别。"}], "进阶": [{"t": "mc", "q": "选出正确的倒装句：", "opts": ["Never I have seen it.", "Never seen I have it.", "Never have I seen it.", "Never I seen have."], "a": 2, "ex": "never 置句首部分倒装。"}, {"t": "mc", "q": "It was ______ he said that made me angry.", "opts": ["that", "which", "what", "how"], "a": 2, "ex": "被强调 what he said。"}, {"t": "fill", "q": "改感叹句：It is fine weather. → ______ fine weather it is!", "a": ["What"], "ex": "weather 不可数，What + 形容词 + 名词。"}, {"t": "mc", "q": "Here ______ !", "opts": ["comes he", "he come", "does he come", "he comes"], "a": 3, "ex": "代词作主语时不倒装：Here he comes。"}, {"t": "mc", "q": "Only in this way ______ the problem.", "opts": ["we can solve", "can we solve", "we solve", "solve we"], "a": 1, "ex": "Only + 状语置句首部分倒装。"}, {"t": "translate", "q": "汉译英：多么有趣的故事啊！", "a": ["What an interesting story!", "What an interesting story it is!"], "ex": "What a(n) + 形容词 + 名词。"}, {"t": "translate", "q": "汉译英：正是他帮助了我。", "a": ["It was he who helped me.", "It was him that helped me."], "ex": "强调句 It is/was...that/who...。"}, {"t": "fill", "q": "用强调句改写：I met him in the park.（强调地点）→ It was ______ ______ ______ I met him.", "a": ["in the park that"], "ex": "强调地点状语。"}, {"t": "mc", "q": "Not until midnight ______ to bed.", "opts": ["he went", "he did go", "went he", "did he go"], "a": 3, "ex": "Not until 置句首部分倒装。"}, {"t": "tf", "q": "主语是代词时，Here/There 引导的句子不倒装。", "a": true, "ex": "Here he comes（不倒装）。"}], "复习": [{"t": "mc", "q": "Only when he came back ______ the truth.", "opts": ["did we know", "we knew", "we did know", "knew we"], "a": 0, "ex": "Only when 从句置句首，主句部分倒装。"}, {"t": "tf", "q": "判断强调句：去掉 It is...that... 句子仍成立则为强调句。", "a": true, "ex": "判断方法。"}, {"t": "fill", "q": "用 It is...that... 强调时间：______ yesterday that I saw him.", "a": ["It was"], "ex": "强调过去时间用 It was。"}, {"t": "mc", "q": "So excited ______ that he couldn't sleep.", "opts": ["he was", "was he", "he is", "is he"], "a": 1, "ex": "So + 形容词置句首部分倒装。"}, {"t": "translate", "q": "汉译英：直到他离开我才知道真相。", "a": ["Not until he left did I know the truth.", "I didn't know the truth until he left."], "ex": "Not until 倒装或正常语序。"}, {"t": "translate", "q": "汉译英：他多么努力工作啊！", "a": ["How hard he works!"], "ex": "How + 副词 + 主谓。"}, {"t": "mc", "q": "Hardly had he arrived ______ it began to rain.", "opts": ["than", "that", "then", "when"], "a": 3, "ex": "hardly...when... 固定搭配。"}, {"t": "fill", "q": "改感叹句：They are very kind. → ______ kind they are!", "a": ["How"], "ex": "感叹形容词用 How。"}, {"t": "mc", "q": "It is health ______ matters most, not wealth.", "opts": ["what", "which one", "that", "how"], "a": 2, "ex": "强调句用 that。"}, {"t": "tf", "q": "否定副词（never, hardly, not only）置句首引起部分倒装。", "a": true, "ex": "助动词提前。"}]}, "ch23": {"入门": [{"t": "mc", "q": "I enjoy ______ music.", "opts": ["listening to", "listen to", "to listen to", "listened to"], "a": 0, "ex": "enjoy 后接动名词。"}, {"t": "tf", "q": "look forward to 中 to 是介词，后接动名词。", "a": true, "ex": "to + doing。"}, {"t": "mc", "q": "He decided ______ abroad.", "opts": ["go", "going", "gone", "to go"], "a": 3, "ex": "decide 后接不定式。"}, {"t": "fill", "q": "用正确形式：He worked hard ______ (pass) the exam.（目的）", "a": ["to pass"], "ex": "不定式作目的状语。"}, {"t": "mc", "q": "Would you mind ______ the window?", "opts": ["open", "opening", "to open", "opened"], "a": 1, "ex": "mind 后接动名词。"}, {"t": "tf", "q": "want, hope, decide 后接动词不定式。", "a": true, "ex": "want/hope/decide to do。"}, {"t": "mc", "q": "It's important ______ English well.", "opts": ["learn", "to learn", "learning", "learned"], "a": 1, "ex": "It's + 形容词 + to do。"}, {"t": "fill", "q": "用正确形式：I'd like ______ (have) a cup of tea.", "a": ["to have"], "ex": "would like to do。"}, {"t": "mc", "q": "He finished ______ his homework.", "opts": ["do", "to do", "doing", "done"], "a": 2, "ex": "finish 后接动名词。"}, {"t": "tf", "q": "finish, enjoy, mind, keep 后接动名词。", "a": true, "ex": "接 doing。"}], "进阶": [{"t": "mc", "q": "______ from the hill, the city looks beautiful.", "opts": ["Seeing", "To see", "See", "Seen"], "a": 3, "ex": "被动关系用过去分词 Seen。"}, {"t": "mc", "q": "The window needs ______.", "opts": ["clean", "to clean", "cleaned", "cleaning"], "a": 3, "ex": "need doing = need to be done。"}, {"t": "fill", "q": "用正确形式：It's no use ______ (cry) over spilt milk.", "a": ["crying"], "ex": "It's no use doing。"}, {"t": "mc", "q": "He kept me ______ for an hour.", "opts": ["wait", "waiting", "to wait", "waited"], "a": 1, "ex": "keep sb doing。"}, {"t": "mc", "q": "The boy was made ______ all day.", "opts": ["work", "working", "to work", "worked"], "a": 2, "ex": "make 被动还原 to。"}, {"t": "translate", "q": "汉译英：我盼望着收到你的来信。", "a": ["I am looking forward to hearing from you."], "ex": "look forward to + doing。"}, {"t": "translate", "q": "汉译英：他努力学习以便取得好成绩。", "a": ["He studies hard to get good grades.", "He works hard in order to get good marks."], "ex": "不定式作目的状语。"}, {"t": "fill", "q": "用正确形式：______ (see) from the moon, the earth looks blue.", "a": ["Seen"], "ex": "earth 与 see 是被动关系，用过去分词。"}, {"t": "mc", "q": "There is nothing ______ here.", "opts": ["to do", "do", "doing", "done"], "a": 0, "ex": "不定式作后置定语。"}, {"t": "tf", "q": "\"stop to do\" 与 \"stop doing\" 含义不同。", "a": true, "ex": "stop to do 停下来去做；stop doing 停止做。"}], "复习": [{"t": "mc", "q": "remember ______ off the lights before you leave.", "opts": ["turning", "to turn", "turn", "turned"], "a": 1, "ex": "remember to do 记得去做（未做）。"}, {"t": "tf", "q": "remember to do 与 remember doing 含义相同。", "a": false, "ex": "to do 未做；doing 做过。"}, {"t": "fill", "q": "用正确形式：______ (finish) the homework, he went out.", "a": ["Having finished"], "ex": "动作先于主句且主动，用现在分词完成式。"}, {"t": "mc", "q": "He pretended ______ asleep.", "opts": ["be", "being", "been", "to be"], "a": 3, "ex": "pretend to do。"}, {"t": "translate", "q": "汉译英：不要忘记关灯。", "a": ["Don't forget to turn off the lights."], "ex": "forget to do 记得去做。"}, {"t": "translate", "q": "汉译英：用这种方式解决问题没有用。", "a": ["It is no use solving the problem in this way.", "It's no use doing it this way."], "ex": "It is no use doing。"}, {"t": "mc", "q": "This problem is worth ______ .", "opts": ["discuss", "to discuss", "discussed", "discussing"], "a": 3, "ex": "be worth doing。"}, {"t": "fill", "q": "用正确形式：The leaves ______ (fall) on the ground are yellow.", "a": ["fallen"], "ex": "fall 不及物，fallen 作定语表\"已落下的\"。"}, {"t": "mc", "q": "He is busy ______ for the exam.", "opts": ["preparing", "prepare", "to prepare", "prepared"], "a": 0, "ex": "be busy doing。"}, {"t": "tf", "q": "使役动词 make/let/have 后接不带 to 的不定式（动词原形）。", "a": true, "ex": "如 make sb do。"}]}, "ch24": {"入门": [{"t": "mc", "q": "The boy ______ under the tree is my brother.", "opts": ["stand", "stands", "standing", "stood"], "a": 2, "ex": "现在分词作后置定语。"}, {"t": "tf", "q": "介词短语、分词、不定式都可作后置定语。", "a": true, "ex": "如 the book on the desk。"}, {"t": "mc", "q": "I have a lot of work ______ today.", "opts": ["do", "to do", "doing", "done"], "a": 1, "ex": "不定式作后置定语。"}, {"t": "fill", "q": "用正确形式：The language ______ (speak) here is English.", "a": ["spoken"], "ex": "被动关系用过去分词。"}, {"t": "mc", "q": "The man ______ a blue coat is my uncle.", "opts": ["wearing", "wear", "wears", "worn"], "a": 0, "ex": "现在分词 wearing 作后置定语。"}, {"t": "tf", "q": "形容词短语可作后置定语，如 a box full of books。", "a": true, "ex": "full of books 后置。"}, {"t": "mc", "q": "Look at the girl ______ long hair.", "opts": ["of", "in", "with", "on"], "a": 2, "ex": "介词短语 with long hair 作后置定语。"}, {"t": "fill", "q": "用正确形式：Do you have anything ______ (say)?", "a": ["to say"], "ex": "不定式作后置定语修饰 anything。"}, {"t": "mc", "q": "The book ______ the table is mine.", "opts": ["in", "at", "on", "of"], "a": 2, "ex": "介词短语 on the table 作后置定语。"}, {"t": "tf", "q": "现在分词作后置定语表主动、进行；过去分词表被动、完成。", "a": true, "ex": "基本区别。"}], "进阶": [{"t": "mc", "q": "Most of the people ______ to the party were students.", "opts": ["invite", "inviting", "to invite", "invited"], "a": 3, "ex": "被动关系用过去分词。"}, {"t": "mc", "q": "The man ______ you talked to is a writer.", "opts": ["which", "whom", "standing", "to talk"], "a": 1, "ex": "关系代词作介词宾语，指人用 whom。"}, {"t": "fill", "q": "用正确形式：Look at the building ______ (build) now.", "a": ["being built"], "ex": "正在被建，用现在分词被动式。"}, {"t": "mc", "q": "The first person ______ the office should turn on the lights.", "opts": ["enter", "entering", "to enter", "entered"], "a": 2, "ex": "序数词后用不定式。"}, {"t": "mc", "q": "This is a problem ______ .", "opts": ["worth to discuss", "worth discussing", "worthy discussing", "worth discussed"], "a": 1, "ex": "be worth doing。"}, {"t": "translate", "q": "汉译英：那个正在打篮球的男孩是我的同学。", "a": ["The boy playing basketball is my classmate.", "The boy who is playing basketball is my classmate."], "ex": "现在分词/定语从句作后置定语。"}, {"t": "translate", "q": "汉译英：这是一个值得参观的地方。", "a": ["This is a place worth visiting.", "This is a place worth a visit."], "ex": "worth + doing 作后置定语。"}, {"t": "fill", "q": "用正确形式：The leaves ______ (fall) on the ground are yellow.", "a": ["fallen"], "ex": "fall 不及物，fallen 表\"已落下\"。"}, {"t": "mc", "q": "He was the only one ______ the meeting.", "opts": ["attend", "attending", "attended", "to attend"], "a": 3, "ex": "the only one 后用不定式。"}, {"t": "tf", "q": "过去分词作后置定语时，相当于一个被动的定语从句。", "a": true, "ex": "the book written by him = which was written by him。"}], "复习": [{"t": "mc", "q": "The students ______ in the classroom are reading.", "opts": ["sit", "sat", "to sit", "sitting"], "a": 3, "ex": "现在分词表主动、进行。"}, {"t": "tf", "q": "\"the way to do sth\" 中不定式作后置定语。", "a": true, "ex": "to do 修饰 way。"}, {"t": "fill", "q": "用正确形式：The questions ______ (discuss) at the meeting are important.", "a": ["discussed"], "ex": "被动关系用过去分词。"}, {"t": "mc", "q": "Have you got anything ______ me?", "opts": ["tell", "telling", "to tell", "told"], "a": 2, "ex": "不定式作后置定语。"}, {"t": "translate", "q": "汉译英：穿白衬衫的那个人是我们的老师。", "a": ["The man in a white shirt is our teacher.", "The man wearing a white shirt is our teacher."], "ex": "介词短语/现在分词作后置定语。"}, {"t": "translate", "q": "汉译英：这是一个用英语写的故事。", "a": ["This is a story written in English.", "This is a story that is written in English."], "ex": "过去分词作后置定语表被动。"}, {"t": "mc", "q": "There were few chances ______ .", "opts": ["lose", "to lose", "losing", "lost"], "a": 1, "ex": "不定式作后置定语。"}, {"t": "fill", "q": "用正确形式：The boy ______ (injure) in the accident was sent to hospital.", "a": ["injured"], "ex": "被动关系用过去分词。"}, {"t": "mc", "q": "He pointed to the house ______ on the hill.", "opts": ["stand", "standing", "stands", "stood"], "a": 1, "ex": "现在分词作后置定语。"}, {"t": "tf", "q": "不定式作后置定语常表示\"将要做的、未完成的\"动作。", "a": true, "ex": "如 work to do。"}]}, "ch25": {"入门": [{"t": "mc", "q": "He was late ______ the heavy traffic.", "opts": ["because", "so", "because of", "therefore"], "a": 2, "ex": "because of + 名词。"}, {"t": "tf", "q": "because 引导句子，because of 后接名词。", "a": true, "ex": "基本区别。"}, {"t": "mc", "q": "It rained, ______ we stayed at home.", "opts": ["because", "so", "for", "therefore"], "a": 1, "ex": "so 表结果。"}, {"t": "fill", "q": "用 so...that：He was ______ tired ______ he couldn't go on.", "a": ["so; that"], "ex": "so + 形容词 + that。"}, {"t": "mc", "q": "He didn't come ______ he was ill.", "opts": ["because of", "so", "therefore", "because"], "a": 3, "ex": "because + 句子。"}, {"t": "tf", "q": "so 表结果，因此不能与 because 同句使用。", "a": true, "ex": "只用其一。"}, {"t": "mc", "q": "He stayed home ______ the rain.", "opts": ["because of", "because", "so", "therefore"], "a": 0, "ex": "because of + 名词。"}, {"t": "fill", "q": "用 because/because of：He failed ______ his laziness.", "a": ["because of"], "ex": "+ 名词用 because of。"}, {"t": "mc", "q": "She was ill, ______ she didn't go to school.", "opts": ["so", "because", "for", "because of"], "a": 0, "ex": "so 表结果。"}, {"t": "tf", "q": "as, since, because 都可引导原因状语从句。", "a": true, "ex": "原因连词。"}], "进阶": [{"t": "mc", "q": "It rained heavily; ______, the match was cancelled.", "opts": ["because", "though", "because of", "therefore"], "a": 3, "ex": "therefore 因此。"}, {"t": "mc", "q": "______ his hard work, he succeeded.", "opts": ["Thanks to", "Because", "So", "Therefore"], "a": 0, "ex": "Thanks to + 名词。"}, {"t": "fill", "q": "用 such...that：It was ______ a cold day ______ we stayed inside.", "a": ["such; that"], "ex": "such + a + 形容词 + 名词 + that。"}, {"t": "mc", "q": "He didn't come, ______ he was ill.", "opts": ["because of", "so", "therefore", "for"], "a": 3, "ex": "for 补充说明原因，置于后。"}, {"t": "mc", "q": "______ he worked hard, he didn't pass.（让步）", "opts": ["Because", "So", "Although", "Thanks to"], "a": 2, "ex": "区分：Although 让步，不表因果。"}, {"t": "translate", "q": "汉译英：由于天气不好，我们取消了旅行。", "a": ["Because of the bad weather, we cancelled the trip.", "We cancelled the trip because of the bad weather."], "ex": "because of + 名词。"}, {"t": "translate", "q": "汉译英：他病了，所以没来上学。", "a": ["He was ill, so he didn't come to school.", "He didn't come to school because he was ill."], "ex": "so 结果 / because 原因。"}, {"t": "fill", "q": "用 thanks to：______ your help, we finished on time.", "a": ["Thanks to"], "ex": "Thanks to + 名词表原因。"}, {"t": "mc", "q": "The game was put off ______ the rain.", "opts": ["because", "because of", "so", "for"], "a": 1, "ex": "because of + 名词。"}, {"t": "tf", "q": "due to, owing to 都可表示\"由于\"，后接名词。", "a": true, "ex": "如 due to the storm。"}], "复习": [{"t": "mc", "q": "The accident was ______ his careless driving.", "opts": ["because", "because of", "so that", "therefore"], "a": 1, "ex": "be + because of + 名词。"}, {"t": "tf", "q": "\"so...that\" 与 \"such...that\" 都可表示因果（结果）。", "a": true, "ex": "结果状语从句。"}, {"t": "fill", "q": "改写：He was ill, so he didn't come. → He didn't come ______ his illness.", "a": ["because of", "owing to", "due to"], "ex": "原因用 because of/owing to + 名词。"}, {"t": "mc", "q": "______ it was getting dark, we went home.", "opts": ["Although", "So", "Therefore", "As"], "a": 3, "ex": "As 引导原因从句。"}, {"t": "translate", "q": "汉译英：多亏了老师的帮助，我才通过了考试。", "a": ["Thanks to my teacher's help, I passed the exam."], "ex": "Thanks to + 名词。"}, {"t": "translate", "q": "汉译英：天太黑了，我们什么也看不见。", "a": ["It was so dark that we could see nothing.", "It was so dark that we couldn't see anything."], "ex": "so...that 结果从句。"}, {"t": "mc", "q": "He couldn't come ______ he was busy.", "opts": ["because of", "so", "because", "therefore"], "a": 2, "ex": "because + 句子。"}, {"t": "fill", "q": "用 so/such：He has ______ many friends that he is never lonely.", "a": ["so"], "ex": "so + many + 复数名词 + that。"}, {"t": "mc", "q": "The flight was delayed ______ the bad weather.", "opts": ["because", "due to", "so", "therefore"], "a": 1, "ex": "due to + 名词。"}, {"t": "tf", "q": "\"so + many/much + 名词 + that\" 可引导结果状语从句。", "a": true, "ex": "so many books that...。"}]}};